(24,'Ms.','Bi.','Zena  Hussein',0,'Kaimu Meneja - Sehemu ya  Mafunzo kwa Njia ya Mtandao','Ag.Manager - Global Learning Section',NULL,NULL,'6f9c156c3740093e03540ddb5e771102.png','zena.hussein@tpsc.go.tz','+255 22 2152982','2023-12-14 09:15:45','2023-12-14 09:50:35','manager-global-learning-section'),(25,'Prof','Prof','Masoud Muruke',0,'Mjumbe wa Bodi','Board Member','<p>Mjumbe wa Bodi</p>','<p>Body Member</p>','147fe1f1158103763bfaa6a6fe1e8deb.png','info@tpsc.go.tz','+255 22 2152982','2023-12-14 09:16:39','2023-12-14 09:16:39','board-member-3'),(26,'Dr.','Dkt.','Florens M. Turuka',0,'Mwenyekiti wa Bodi','Board Chairman',NULL,NULL,'014cc59623d6e5ce4409b2427fef6404.png','info@tpsc.go.tz','+255 22 2152982','2023-12-14 09:25:00','2023-12-14 09:25:00','board-chairman'),(27,'Mr.','Bw.','Baraka Mwabenga',0,'Kaimu Mkurugenzi wa Utawala na Rasilimali Watu','Ag. Director of Human Resource and Administration',NULL,NULL,'fbb87dc09bba37f079b95881ad388b1d.jpeg','baraka.mwabenga@tpsc.go.tz','0784389720','2023-12-19 05:08:41','2023-12-19 07:48:05','ag-director-of-human-resource-and-administration'),(28,'Dr.','Dkt.','Emmanuel Tandika',0,'Mkurugenzi wa Kampasi - Singida','Campus Director - Singida','<p style=\"text-align: justify;\">Dr. Emmanuel Tandika (PhD) is a lecturer at the Tanzania Public Service College (TPSC). He obtained his undergraduate degree (Bachelor of Arts in Education) in 2005 from the University of Dar es Salaam. He received his postgraduate Diploma in Human Resource Management in 2008 from the Institute of Finance Management (IFM) under the mentorship and guidance of Dr. Mwanjabala. He also received Master degree in Business Administration (MBA) with specialization in Human Resource management in 2010 from the University of Dar es Salaam. Dr. Tandika received his PhD in Business Administration with specialization in Human Resource Management in 2022 from the University of Dar es Salaam. In 2023, he was promoted from Assistant Lecturer to Lecturer level.</p>\r\n\r\n<p style=\"text-align: justify;\"><br />\r\nDr. Tandika has attended various career development trainings, conferences, workshops and seminars including international conferences on African Entrepreneurship and Small Business Development, Business Process Re-Engineering , Research and Consultancy Skills Development, Application of Free and Open Source Software to Enhance Research Capacity and E-Learning in Tanzania, Qualitative Data Analysis Using MAXQDA 2020 package, General Applicability of New Labour Laws, Competence-Based Learning Cursus (CEBET), Competency-Based Employee Selection Programme, Training on Advocacy and Lobbying and other National and international trainings.<br />\r\nDr. Tandika has been involved in facilitating various Management and Human Resource programmes in various colleges including Institute of Social Work (DSM), Tanzania Institute of Accountancy (DSM) and Tanzania Public Service College (DSM Campus). He has been involved in various collaborative research projects including the Research on Minimum Wage Bills conducted by TPSC and the ongoing Research in finding out the source of conflict among presidential appointees in Local Government Authorities in Tanzania. He has published papers in national and international journals including ORSEA Journal and Journal of Healthcare Administration. He was awarded a certificate of appreciation as the first winner in essay completion East Africa on &ldquo;Kiswahili, Utandawazi na Umoja wa Africa&rdquo; in 2005 and a certificate of appreciation as the first winner in Tanzania in essay competition on &ldquo;Child Domestic Labour&rdquo; conducted by Kuleana, Mwanza in 2004.</p>\r\n\r\n<p style=\"text-align: justify;\"><br />\r\n&nbsp;In Management, Dr. Tandika has been promoted to various positions. He served as a Coordinator in the Department of Records, Archives and Information Studies (2012-2013); Manager of Programmes (MOP) &ndash; TPSC- DSM Campus (2013-2014); Quality Assurance Manager (2014-2015) and currently he serves as a Campus Director, TPSC-Singida Campus.&nbsp;<br />\r\n&nbsp;</p>','<p style=\"text-align:justify\">Dr. Emmanuel Tandika (PhD) is a lecturer at the Tanzania Public Service College (TPSC). He obtained his undergraduate degree (Bachelor of Arts in Education) in 2005 from the University of Dar es Salaam. He received his postgraduate Diploma in Human Resource Management in 2008 from the Institute of Finance Management (IFM) under the mentorship and guidance of Dr. Mwanjabala. He also received Master degree in Business Administration (MBA) with specialization in Human Resource management in 2010 from the University of Dar es Salaam. Dr. Tandika received his PhD in Business Administration with specialization in Human Resource Management in 2022 from the University of Dar es Salaam. In 2023, he was promoted from Assistant Lecturer to Lecturer level.</p>\r\n\r\n<p style=\"text-align:justify\"><br />\r\nDr. Tandika has attended various career development trainings, conferences, workshops and seminars including international conferences on African Entrepreneurship and Small Business Development, Business Process Re-Engineering , Research and Consultancy Skills Development, Application of Free and Open Source Software to Enhance Research Capacity and E-Learning in Tanzania, Qualitative Data Analysis Using MAXQDA 2020 package, General Applicability of New Labour Laws, Competence-Based Learning Cursus (CEBET), Competency-Based Employee Selection Programme, Training on Advocacy and Lobbying and other National and international trainings.<br />\r\nDr. Tandika has been involved in facilitating various Management and Human Resource programmes in various colleges including Institute of Social Work (DSM), Tanzania Institute of Accountancy (DSM) and Tanzania Public Service College (DSM Campus). He has been involved in various collaborative research projects including the Research on Minimum Wage Bills conducted by TPSC and the ongoing Research in finding out the source of conflict among presidential appointees in Local Government Authorities in Tanzania. He has published papers in national and international journals including ORSEA Journal and Journal of Healthcare Administration. He was awarded a certificate of appreciation as the first winner in essay completion East Africa on &ldquo;Kiswahili, Utandawazi na Umoja wa Africa&rdquo; in 2005 and a certificate of appreciation as the first winner in Tanzania in essay competition on &ldquo;Child Domestic Labour&rdquo; conducted by Kuleana, Mwanza in 2004.</p>\r\n\r\n<p style=\"text-align:justify\"><br />\r\n&nbsp;In Management, Dr. Tandika has been promoted to various positions. He served as a Coordinator in the Department of Records, Archives and Information Studies (2012-2013); Manager of Programmes (MOP) &ndash; TPSC- DSM Campus (2013-2014); Quality Assurance Manager (2014-2015) and currently he serves as a Campus Director, TPSC-Singida Campus.&nbsp;</p>','1191473d16cf015cd4c3b987396d1942.jpeg','emmanuel.tandika@tpsc.go.tz','0784403772','2023-12-19 05:20:51','2024-01-09 18:58:03','director-4'),(29,'Ms.','Bi.','Felister Akonaay',0,'Mkurugenzi wa Kampasi - Tabora','Campus Director - Tabora',NULL,NULL,'e19e0686243eb43f400dbc6e54e6ef3c.jpeg','felister.akonaay@tpsc.go.tz','0716116052','2023-12-19 05:33:58','2023-12-19 05:33:58','campus-director-tabora'),(30,'CPA.','CPA.','Steven Sibuti',0,'Kaimu Meneja  Fedha na Uhasibu','Ag.Finance and Accounts Manager','<p>Steven Sibuti</p>','<p>Steven Sibuti</p>','25342e6b52eaeb2d6f8c1a8914c6aabb.jpeg','steven.sibuti@tpsc.go.tz','Telephone:+255 22 2152982','2023-12-19 05:47:12','2023-12-19 06:01:49','ag-finance-and-accounts-manager'),(31,'Ms.','Bi.','Mwanaidi Mdee',0,'Kaimu Meneja Mipango na Maendeleo','Ag.Planning and Development Manager',NULL,NULL,'b7813a0390811d329d03ef270f05daf5.jpeg','mwanaidi.mdee@tpsc.go.tz','+255 22 2152982','2023-12-19 06:13:33','2023-12-19 06:13:33','ag-planning-and-development-manager'),(32,'Dr.','Dkt.','Charles T. Rwekaza',0,'Meneja Utafiti na Ushauri','Manager of Research, Publication and Consultancy',NULL,NULL,'ac3cdbd749a91501d70fe2738752247d.jpeg','charles.rwekaza@tpsc.go.tz','+255 22 2152982','2023-12-19 06:21:30','2023-12-19 06:21:30','manager-of-research-publication-and-consultancy'),(33,'Mr.','Bw.','Saidy Nzagamba',0,'Mkurugenzi wa Kampasi - Mbeya','Campus Director - Mbeya',NULL,NULL,'da6672a260d347f96ec3eecad4689534.jpeg','saidy.nzagamba@tpsc.go.tz','+255-252502627','2023-12-19 06:59:34','2023-12-19 06:59:34','campus-director-mbeya'),(34,'CPA','CPA','Freddy George Chuwa',0,'Mkuu wa Kitengo cha Ukaguzi wa Ndani','Head of Internal Audit',NULL,NULL,'2b292353b8b5bc4bec63e48c616ff746.jpeg','freddy.chuwa@tpsc.go.tz','+255 22 2152982','2023-12-19 08:30:00','2023-12-19 08:30:00','head-of-internal-audit');
