INSERT INTO `announcements` VALUES (6,'MAHAFALI YA 38 YA CHUO CHA UTUMISHI WA UMMA TANZANIA (TPSC)','MAHAFALI YA 38 YA CHUO CHA UTUMISHI WA UMMA TANZANIA (TPSC)','<p>Kaimu Mkuu wa Chuo na Mtendaji Mkuu wa Chuo cha Utumishi wa Umma Tanzania anapenda kuwatangazia wahitimu wote na wadau wa Chuo cha Utumishi wa Umma kwa ujumla kuwa Mahafali ya Thelathini na Nane (38) kwa Kampasi zote za Chuo cha Utumishi wa Umma yatafanyika siku ya Ijumaa , tarehe 24 Novemba 2023 katika viwanja vya Chuo cha Utumishi wa Umma Kampasi ya Tabora, kuanzia saa tatu (03.00) asubuhi.</p>\r\n\r\n<p>Mgeni Rasmi anatarajiwa kuwa Waziri wa Nchi, Ofisi ya Rais, Menejimenti ya Utumishi wa Umma na Utawala Bora, Mh. Mhe. George B. Simbachawene (MB).</p>\r\n\r\n<p>Majina ya wahitimu yanapatakana kwenye tuvuti ya Chuo&nbsp;<strong>(</strong><em><a href=\"http://www.tpsc.go.tz/\">www.tpsc.go.tz</a></em><strong>).</strong></p>\r\n\r\n<p>Aidha, wahitimu wote wanahimizwa kuhudhuria mahafali hayo. Mazoezi (Rehearsal) yatafanyika siku ya Alhamisi tarehe 23 Novemba 2023 katika Kampasi ya Tabora saa nane (08.00) mchana.</p>\r\n\r\n<p>Wahitimu wanatakiwa kuvaa suti zinazokubalika Chuoni (nyeusi au dark blue). Gharama ya Joho ni shilingi 30,000 kwa wahitimu wa Shahada ya kwanza na Skafu shilingi 10,000 kwa wahitimu wa Cheti na Stashahada.</p>\r\n\r\n<p>Aidha, wahitimu mnatakiwa kuthibitisha ushiriki wenu kupitia namba. 0717152111 /0764775034/0784680077/071757452/0717574525</p>\r\n\r\n<p><strong>IMETOLEWA NA:</strong></p>\r\n\r\n<p>KITENGO CHA MAWASILIANO NA MASOKO</p>','<p>Kaimu Mkuu wa Chuo na Mtendaji Mkuu wa Chuo cha Utumishi wa Umma Tanzania anapenda kuwatangazia wahitimu wote na wadau wa Chuo cha Utumishi wa Umma kwa ujumla kuwa Mahafali ya Thelathini na Nane (38) kwa Kampasi zote za Chuo cha Utumishi wa Umma yatafanyika siku ya Ijumaa , tarehe 24 Novemba 2023 katika viwanja vya Chuo cha Utumishi wa Umma Kampasi ya Tabora, kuanzia saa tatu (03.00) asubuhi.</p>\r\n\r\n<p>Mgeni Rasmi anatarajiwa kuwa Waziri wa Nchi, Ofisi ya Rais, Menejimenti ya Utumishi wa Umma na Utawala Bora, Mh. Mhe. George B. Simbachawene (MB).</p>\r\n\r\n<p>Majina ya wahitimu yanapatakana kwenye tuvuti ya Chuo&nbsp;<strong>(</strong><em><a href=\"http://www.tpsc.go.tz/\">www.tpsc.go.tz</a></em><strong>).</strong></p>\r\n\r\n<p>Aidha, wahitimu wote wanahimizwa kuhudhuria mahafali hayo. Mazoezi (Rehearsal) yatafanyika siku ya Alhamisi tarehe 23 Novemba 2023 katika Kampasi ya Tabora saa nane (08.00) mchana.</p>\r\n\r\n<p>Wahitimu wanatakiwa kuvaa suti zinazokubalika Chuoni (nyeusi au dark blue). Gharama ya Joho ni shilingi 30,000 kwa wahitimu wa Shahada ya kwanza na Skafu shilingi 10,000 kwa wahitimu wa Cheti na Stashahada.</p>\r\n\r\n<p>Aidha, wahitimu mnatakiwa kuthibitisha ushiriki wenu kupitia namba. 0717152111 /0764775034/0784680077/071757452/0717574525</p>\r\n\r\n<p><strong>IMETOLEWA NA:</strong></p>\r\n\r\n<p>KITENGO CHA MAWASILIANO NA MASOKO</p>',1,'mahafali-ya-38-ya-chuo-cha-utumishi-wa-umma-tanzania-tpsc','2023-12-15 09:05:23','2023-12-15 09:05:23'),(7,'Mitihani ya watumishi wa Umma - Machi, 2024','Public Service Examinations - March, 2024','<p><span style=\"font-size:11pt\"><span style=\"background-color:white\"><span style=\"font-family:Calibri,\">Tanzania Public Service College (TPSC) is informing all the Public Service Examination Candidates that, the standard review courses for PSE will start on 19<sup>th</sup> February, 2024 to 8<sup>th</sup> March, 2024 at TPSC Dar es Salaam, Tabora, Mtwara Singida, Tanga and Mbeya Campuses. However, the Examinations (PSE) will be held from 11<sup>th</sup> to 15<sup>th</sup> &nbsp;&nbsp;March, 2024.</span></span></span></p>','<p><span style=\"font-size:11pt\"><span style=\"background-color:white\"><span style=\"font-family:Calibri,\">Tanzania Public Service College (TPSC) is informing all the Public Service Examination Candidates that, the standard review courses for PSE will start on 19<sup>th</sup> February, 2024 to 8<sup>th</sup> March, 2024 at TPSC Dar es Salaam, Tabora, Mtwara Singida, Tanga and Mbeya Campuses. However, the Examinations (PSE) will be held from 11<sup>th</sup> to 15<sup>th</sup> &nbsp;&nbsp;March, 2024.</span></span></span></p>',1,'public-service-examinations','2023-12-15 09:11:53','2023-12-15 09:14:03'),(8,'Kufunguliwa kwa Udahili Mkupuo wa Machi 2024','Opening of Application for March 2024 Intake.','<p style=\"text-align:justify\">Donec lacinia ante non libero dignissim, quis gravida velit venenatis. Sed auctor tincidunt venenatis. Ut vitae posuere mi. Morbi semper sagittis rhoncus. Fusce aliquam vitae orci scelerisque aliquam. Suspendisse porta urna at neque ullamcorper bibendum. Pellentesque rhoncus erat augue, in cursus sem luctus eu. Curabitur sem dui, sagittis ac purus quis, cursus porta velit. Vestibulum ante ipsum primis in faucibus orci luctus et ultrices posuere cubilia curae; Duis facilisis a ligula sit amet dapibus.</p>','<p style=\"text-align:justify\">Donec lacinia ante non libero dignissim, quis gravida velit venenatis. Sed auctor tincidunt venenatis. Ut vitae posuere mi. Morbi semper sagittis rhoncus. Fusce aliquam vitae orci scelerisque aliquam. Suspendisse porta urna at neque ullamcorper bibendum. Pellentesque rhoncus erat augue, in cursus sem luctus eu. Curabitur sem dui, sagittis ac purus quis, cursus porta velit. Vestibulum ante ipsum primis in faucibus orci luctus et ultrices posuere cubilia curae; Duis facilisis a ligula sit amet dapibus.</p>',1,'opening-of-application-for-march-2024','2023-12-15 09:19:43','2023-12-15 09:20:13'),(10,'Tangazo Jipya linakaa hapa kwa wateja kuona','New Announcement stays here for viewers to see','<p style=\"text-align:justify\">Contrary to popular belief, Lorem Ipsum is not simply random text. It has roots in a piece of classical Latin literature from 45 BC, making it over 2000 years old. Richard McClintock, a Latin professor at Hampden-Sydney College in Virginia, looked up one of the more obscure Latin words, consectetur, from a Lorem Ipsum passage, and going through the cites of the word in classical literature, discovered the undoubtable source. Lorem Ipsum comes from sections 1.10.32 and 1.10.33 of &quot;de Finibus Bonorum et Malorum&quot; (The Extremes of Good and Evil) by Cicero, written in 45 BC. This book is a treatise on the theory of ethics, very popular during the Renaissance. The first line of Lorem Ipsum, &quot;Lorem ipsum dolor sit amet..&quot;, comes from a line in section 1.10.32.</p>','<p>Contrary to popular belief, Lorem Ipsum is not simply random text. It has roots in a piece of classical Latin literature from 45 BC, making it over 2000 years old. Richard McClintock, a Latin professor at Hampden-Sydney College in Virginia, looked up one of the more obscure Latin words, consectetur, from a Lorem Ipsum passage, and going through the cites of the word in classical literature, discovered the undoubtable source. Lorem Ipsum comes from sections 1.10.32 and 1.10.33 of &quot;de Finibus Bonorum et Malorum&quot; (The Extremes of Good and Evil) by Cicero, written in 45 BC. This book is a treatise on the theory of ethics, very popular during the Renaissance. The first line of Lorem Ipsum, &quot;Lorem ipsum dolor sit amet..&quot;, comes from a line in section 1.10.32.</p>',0,'new-announcement','2024-01-15 13:59:37','2024-01-15 14:21:32'),(11,'Opening of Application for March 2024 Intake.','Opening of Application for March 2024 Intake.','<p style=\"text-align: justify;\">Contrary to popular belief, Lorem Ipsum is not simply random text. It has roots in a piece of classical Latin literature from 45 BC, making it over 2000 years old. Richard McClintock, a Latin professor at Hampden-Sydney College in Virginia, looked up one of the more obscure Latin words, consectetur, from a Lorem Ipsum passage, and going through the cites of the word in classical literature, discovered the undoubtable source. Lorem Ipsum comes from sections 1.10.32 and 1.10.33 of &quot;de Finibus Bonorum et Malorum&quot; (The Extremes of Good and Evil) by Cicero, written in 45 BC. This book is a treatise on the theory of ethics, very popular during the Renaissance. The first line of Lorem Ipsum, &quot;Lorem ipsum dolor sit amet..&quot;, comes from a line in section 1.10.32.</p>','<p style=\"text-align: justify;\">Contrary to popular belief, Lorem Ipsum is not simply random text. It has roots in a piece of classical Latin literature from 45 BC, making it over 2000 years old. Richard McClintock, a Latin professor at Hampden-Sydney College in Virginia, looked up one of the more obscure Latin words, consectetur, from a Lorem Ipsum passage, and going through the cites of the word in classical literature, discovered the undoubtable source. Lorem Ipsum comes from sections 1.10.32 and 1.10.33 of &quot;de Finibus Bonorum et Malorum&quot; (The Extremes of Good and Evil) by Cicero, written in 45 BC. This book is a treatise on the theory of ethics, very popular during the Renaissance. The first line of Lorem Ipsum, &quot;Lorem ipsum dolor sit amet..&quot;, comes from a line in section 1.10.32.</p>',1,'opening-of-application-for-march-2024-intake','2024-01-15 14:02:54','2024-01-15 14:02:54');
