INSERT INTO `media` VALUES (39,'','','Naibu Waziri Ofisi ya Rais, Menejimenti ya Utumishi wa Umma na Utawala Bora Mhe. Ridhiwani Kikwete akizungumza Wajumbe wa Kamati ya Kusimamia Ofisi za Viongozi Wakuu wa Kitaifa ya Baraza la Wawakilishi Zanzibar waliofanya ziara katika Ofisi ya za Idara ya Kumbukumbu na Nyaraka za Taifa Jijini Dar es Salaam tarehe 11 Desemba, 2023','Naibu Waziri Ofisi ya Rais, Menejimenti ya Utumishi wa Umma na Utawala Bora Mhe. Ridhiwani Kikwete akizungumza Wajumbe wa Kamati ya Kusimamia Ofisi za Viongozi Wakuu wa Kitaifa ya Baraza la Wawakilishi Zanzibar waliofanya ziara katika Ofisi ya za Idara ya Kumbukumbu na Nyaraka za Taifa Jijini Dar es Salaam tarehe 11 Desemba, 2023','images/jpeg','/uploads/gallery/','','a94490c8af453843e8d91c7e43934aa4.jpeg','','a94490c8af453843e8d91c7e43934aa4-jpeg',0,8,1,'2023-12-13 10:04:09','2023-12-13 10:04:09'),(40,'','','Mkurugenzi wa Idara ya Utawala wa Utumishi wa Umma, Ofisi ya Rais, Menejimenti ya Utumishi wa Umma na Utawala Bora ambaye pia ni Msimamizi Mkuu wa Mafunzo ya PEPMIS, PIPMIS na HR Assesment kwa Mkoa wa Dodoma Bi. Felista Shuli akizungumza na Viongozi na Watumishi wa Wizara ya Fedha wakati akifungua Mafunzo ya Mifumo hiyo katika Ukumbi wa Hazina jijini Dodoma tarehe 12 Desemba, 2023.','Mkurugenzi wa Idara ya Utawala wa Utumishi wa Umma, Ofisi ya Rais, Menejimenti ya Utumishi wa Umma na Utawala Bora ambaye pia ni Msimamizi Mkuu wa Mafunzo ya PEPMIS, PIPMIS na HR Assesment kwa Mkoa wa Dodoma Bi. Felista Shuli akizungumza na Viongozi na Watumishi wa Wizara ya Fedha wakati akifungua Mafunzo ya Mifumo hiyo katika Ukumbi wa Hazina jijini Dodoma tarehe 12 Desemba, 2023.','images/jpeg','/uploads/gallery/','','d1341d427bede4f9cb0d5a6ba1023906.jpeg','','d1341d427bede4f9cb0d5a6ba1023906-jpeg',0,8,1,'2023-12-13 10:06:25','2023-12-13 10:06:25'),(41,'','','','','images/jpeg','/uploads/gallery/','','47bf55c2f1bfb43dd2e8c9a12eeb2432.jpeg','','47bf55c2f1bfb43dd2e8c9a12eeb2432-jpeg',0,10,1,'2023-12-13 10:22:46','202