  `summary_en` text COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `content_sw` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `content_en` text COLLATE utf8mb4_unicode_ci DEFAULT NULL,
