  UNIQUE KEY `studentID` (`studentID`),
  KEY `program` (`program`),
  CONSTRAINT `student_ibfk_1` FOREIGN KEY (`program`) REFERENCES `program` (`progID`) ON DELETE SET NULL ON UPDATE CASCADE
