7:14:09','2023-12-14 07:14:09'),(1161,6,'AdministrationCategories','store','41.59.251.78','http://demo81.eganet.go.tz/tpsc/cms/administration_categories','{\"title_sw\":\"Bodi ya Ushauri\",\"title_en\":\"Ministerial Advisory Board\",\"summary_sw\":\"Bodi ya Ushauri\",\"summary_en\":\"Ministerial Advisory Board\",\"slug\":\"ministerial-advisory-board\"}','2023-12-14 07:26:39','2023-12-14 07:26:39'),(1162,6,'AdministrationCategories','store','41.59.251.78','http://demo81.eganet.go.tz/tpsc/cms/administration_categories','{\"title_sw\":\"Menejimenti\",\"title_en\":\"Management Team\",\"summary_sw\":\"Manajimenti\",\"summary_en\":\"Management Team\",\"slug\":\"management-team\"}','2023-12-14 07:27:19','2023-12-14 07:27:19'),(1163,6,'AdministrationCategories','update','41.59.251.78','http://demo81.eganet.go.tz/tpsc/cms/administration_categories/5','{\"id\":5,\"title_sw\":\"Menejimenti\",\"title_en\":\"Management Team\",\"summary_sw\":\"Manejimenti\",\"summary_en\":\"Management Team\",\"slug\":\"management-team\",\"content\":null,\"active\":1,\"created_at\":\"2023-12-14T10:27:19.000000Z\",\"updated_at\":\"2023-12-14T10:27:19.000000Z\"}','2023-12-14 07:28:21','2023-12-14 07:28:21'),(1164,6,'Administration','store','41.59.251.78','http://demo81.eganet.go.tz/tpsc/cms/administration','{\"salutation_sw\":\"Dkt.\",\"salutation_en\":\"Dr\",\"fullname\":\"Ernest Francis Mabonesho\",\"title_sw\":\"Mkuu wa Chuo na Mtendaji Mkuu\",\"title_en\":\"Rector and Chief Executive Officer\",\"email\":\"info@tpsc.go.tz\",\"phone\":\"+255 22 2152982\",\"position\":\"1\",\"content_sw\":\"<p>Dkt. Ernest Francis Mabonesho<br \\/>\\r\\nKaimu Mkuu wa Chuo<\\/p>\",\"content_en\":\"<p>Dkt. Ernest Francis Mabonesho<br \\/>\\r\\nKaimu Mkuu wa Chuo<\\/p>\",\"photo_url\":\"8dbc31249679cd75e4bc486c03d4ece0.png\",\"slug\":\"rector-and-chief-executive-officer\"}','2023-12-14 07:32:11','2023-12-14 07:32:11'),(1165,6,'Administration','update','41.59.251.78','http://demo81.eganet.go.tz/tpsc/cms/administration/11','{\"id\":11,\"salutation_en\":\"Dr\",\"salutation_sw\":\"Dkt.\",\"fullname\":\"Ernest Francis Mabonesho\",\"position\":\"1\",\"title_sw\":\"Mkuu wa Chuo na Mtendaji Mkuu\",\"title_en\":\"Rector and Chief Executive Officer\",\"content_sw\":\"<p>Dkt. Ernest Francis Mabonesho<br \\/>\\r\\nKaimu Mkuu wa Chuo<\\/p>\\r\\n\\r\\n<p style=\\\"text-align: justify;\\\"><strong>Lorem Ipsum<\\/strong> is simply dummy text of the printing and typesetting industry. Lorem Ipsum has been the industry&#39;s standard dummy text ever since the 1500s, when an unknown printer took a galley of type and scrambled it to make a type specimen book. It has survived not only five centuries, but also the leap into electronic typesetting, remaining essentially unchanged. It was popularised in the 1960s with the release of Letraset sheets containing Lorem Ipsum passages, and more recently with desktop publishing software like Aldus PageMaker including versions of Lorem Ipsum.<\\/p>\",\"content_en\":\"<p>Dkt. Ernest Francis Mabonesho<br \\/>\\r\\nKaimu Mkuu wa Chuo<\\/p>\\r\\n\\r\\n<p style=\\\"text-align: justify;\\\"><strong>Lorem Ipsum<\\/strong> is simply dummy text of the printing and typesetting industry. Lorem Ipsum has been the industry&#39;s standard dummy text ever since the 1500s, when an unknown printer took a galley of type and scrambled it to make a type specimen book. It has survived not only five centuries, but also the leap into electronic typesetting, remaining essentially unchanged. It was popularised in the 1960s with the release of Letraset sheets containing Lorem Ipsum passages, and more recently with desktop publishing software like Aldus PageMaker including versions of Lorem Ipsum.<\\/p>\",\"photo_url\":\"8dbc31249679cd75e4bc486c03d4ece0.png\",\"email\":\"info@tpsc.go.tz\",\"phone\":\"+255 22 2152982\",\"created_at\":\"2023-12-14T10:32:11.000000Z\",\"updated_at\":\"2023-12-14T10:32:11.000000Z\",\"slug\":\"rector-and-chief-executive-officer\"}','2023-12-14 07:34:00','2023-12-14 07:34:00'),(1166,6,'WelcomeNote','update','41.59.251.78','http://demo81.eganet.go.tz/tpsc/cms/welcome/2','{\"id\":2,\"summary_en\":null,\"summary_sw\":null,\"content_sw\":\"<p style=\\\"text-align: justify;\\\">Chuo cha Utumishi wa Umma Tanzania (TPSC) kilianzishwa mwaka 2000 kwa sheria ya Wakala za Serikali Na. 30 ya mwaka 1997. Lengo la kuanzishwa kwake lilikuwa kuziba pengo la kuwa na taasisi ya mafunzo jumuishi kwa utumishi wa umma kukidhi mahitaji yanayobadilika ya utumishi wa umma yaliyosababishwa na maboresho ya utumishi wa umma na haja ya kuwa na chuo cha utumishi wa umma kinachojitegemea chenye uwezo wa fedha endelevu.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align: justify;\\\">Kutokana na hali hiyo, TPSC ni mtoa huduma ya maarifa na stadi anayependelewa kwa utumishi wa umma katika maeneo ya uongozi, Usimamizi wa Kimkakati, Utawala, maadili na uwajibika. Pia ni taasisi ya kujenga utamaduni wa elimu endelevu kwa watumishi wa umma. Wateja wa TPSC ni pamoja na Serikali Kuu na Serikali za Mitaa, idara zinzojitegemea, Wakala za Serikali, wanaohitimu elimu ya Sekondari, umma kwa jumla na sekta binafsi.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align: justify;\\\">TPSC ina Kampasi sita zilizojengwa kimkakati jijini Dar es Salaam, Tabora, Mtwara, Singida, Tanga na Mbeya ili iwe karibu na wateja wake nchi nzima.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align: justify;\\\">Taasisi inatoa masomo katika viwango vitatu vya Cheti (Basic Technician Certificate), Diploma na Shahada ya Kwanza (BA) myanayofaa kwa sekta ya umma na binafsi katika Kampasi zake.Licha ya Programu hizo, TPSCinatoa masomo ya mapitio kwa ajili ya Mitihani ya Utumishi wa Umma na Huduma za Ushauri.Hivi karibuni imeanza ktumika mtindo wa Elimu na Mafunzo yanayotokana na Weledi. (CBET) kama njia ya maendeleo, namna ya kupata Elimu bora na Mafunzo yanayokidhi mahitaji ya soko la ajira la kudumu na linalo haraka sana.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align: justify;\\\">Chuo cha utumishi wa umma Tanzania kimesanifu upya tovuti yakekwa manufaa ya wateja, wadau na umma kwa jumla. Tovuti hii ni chombo cha kupasha habari kinachokusudiakuuarifu umma kwa jumlakuhusu Chuo cha Utumishi umma, huduma inazozitoa, muundo wake na shughuli za chuo kwa jumla.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align: justify;\\\">Inatarajiwa kwamba, tovuti hii iliyoboreshwa itakuwa chanzo cha taarifa kinachofaa kwa wateja wetu, wadau na umma kwa jumla.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align: justify;\\\">Tunawakaribisha wote mtembelee tovuti yetu.<a href=\\\"http:\\/\\/www.tpsc.go.tz\\/\\\"><u>www.tpsc.go.tz<\\/u><\\/a><\\/p>\",\"content_en\":\"<p style=\\\"text-align: justify;\\\">The Tanzania Public Service College (TPSC) is a Technical Institutions in Tanzania was established in 2000 under the ambit of the Executive Agencies Act No 30 of 1997. The aim of it&rsquo;s establishment was to fill an extant void in terms of a comprehensive training facility for Public Service, to meet the changing needs of the Public Services resulted from the Public Service Reforms, and the need for an autonomous financially sustainable public service College.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align: justify;\\\">It is in light of the above that the TPSC is the preferred service provider of knowledge and skills to the public service, but also as a part of building a culture of continuous learning for public servants. The customers of TPSC include; central and local government, independent departments, executive agencies; secondary school leavers, the general public and private sector.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align: justify;\\\">TPSC has&nbsp;<strong>Six Campuses&nbsp;<\\/strong>strategically located in&nbsp;<strong>Dar es Salaam<\\/strong><strong>, Tabora, Mtwara, Singida, Tanga and Mbeya&nbsp;<\\/strong>to be close to its customers countrywide<strong>.<\\/strong><\\/p>\\r\\n\\r\\n<p style=\\\"text-align: justify;\\\">The Institute is offering Basic Technician Certificate, Diploma, and Bachelor Degree Programmes suitable for public and private sectors in its campuses. Besides these programmes, TPSC is offering review classes for Public Service Examinations and consultancy services. It has recently adopted the Competence-Based Education and Training (CBET) approach as the way forward, the way to attain the quality of education and training that meets the demands of a dynamic and permanently changing labour market.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align: justify;\\\">TPSC has redesigned its website to take in to consideration the various improvements taking place in its core activities. We believe this Website will be an informative tool to inform and educated the general public about the Tanzania Public Service College, the products and services offered organization structure and the overall operation of the College.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align: justify;\\\">It is our expectations that, this improved website will be useful to our customers, stakeholders, general public and the rest.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align: justify;\\\">We welcome you all to visit our website at:&nbsp;<a href=\\\"http:\\/\\/www.tpsc.go.tz\\/\\\"><u>www.tpsc.go.tz<\\/u><\\/a>.<\\/p>\",\"status\":\"1\",\"created_at\":\"2022-02-07T13:27:45.000000Z\",\"updated_at\":\"2022-02-07T10:27:45.000000Z\"}','2023-12-14 07:34:08','2023-12-14 07:34:08'),(1167,6,'Administration','store','41.222.179.24','http://demo81.eganet.go.tz/tpsc/cms/administration','{\"salutation_sw\":\"Bw.\",\"salutation_en\":\"Mr\",\"fullname\":\"Shakiru Abdulkarim\",\"title_sw\":\"Mkuu wa Kitengo cha Mawasiliano na Masoko\",\"title_en\":\"Head of Communication and Marketinging\",\"email\":\"abdulkarim.shakiru@tpsc.go.tz\",\"phone\":\"+2556542428\",\"position\":\"0\",\"content_sw\":null,\"content_en\":null,\"photo_url\":\"ae1c3a3259625c377d40269bd5704d76.png\",\"slug\":\"head-of-communication-and-marketinging\"}','2023-12-14 08:31:59','2023-12-14 08:31:59'),(1168,6,'Administration','store','41.222.179.24','http://demo81.eganet.go.tz/tpsc/cms/administration','{\"salutation_sw\":\"Bw.\",\"salutation_en\":\"Mr.\",\"fullname\":\"Mussa Lugembe\",\"title_sw\":\"Mkurugenzi wa Kampasi - Dar es Salaam\",\"title_en\":\"Campus Director - Dar es Salaam\",\"email\":\"mussa.lugembe@tpsc.go.tz\",\"phone\":\"+255 22 2152982\",\"position\":\"0\",\"content_sw\":null,\"content_en\":null,\"photo_url\":\"e4e60fbd003f43e2fbdf58ad550bc491.png\",\"slug\":\"campus-director-dar-es-salaam\"}','2023-12-14 08:36:44','2023-12-14 08:36:44'),(1169,6,'Administration','update','41.222.179.24','http://demo81.eganet.go.tz/tpsc/cms/administration/12','{\"id\":12,\"salutation_en\":\"Mr\",\"salutation_sw\":\"Bw.\",\"fullname\":\"Shakiru Abdulkarim\",\"position\":\"0\",\"title_sw\":\"Mkuu wa Kitengo cha Mawasiliano na Masoko\",\"title_en\":\"Head of Communication and Marketing\",\"content_sw\":null,\"content_en\":null,\"photo_url\":\"ae1c3a3259625c377d40269bd5704d76.png\",\"email\":\"abdulkarim.shakiru@tpsc.go.tz\",\"phone\":\"+2556542428\",\"created_at\":\"2023-12-14T11:31:59.000000Z\",\"updated_at\":\"2023-12-14T11:31:59.000000Z\",\"slug\":\"head-of-communication-and-marketinging\"}','2023-12-14 08:38:02','2023-12-14 08:38:02'),(1170,6,'Administration','store','197.250.227.76','http://demo81.eganet.go.tz/tpsc/cms/administration','{\"salutation_sw\":\"Mr\",\"salutation_en\":\"Mr\",\"fullname\":\"Jovinus Christopher\",\"title_sw\":\"Ag.HPMU\",\"title_en\":\"Ag.HPMU\",\"email\":\"info@tpsc.go.tz\",\"phone\":\"+255 22 2152982\",\"position\":\"0\",\"content_sw\":\"<p>Acting Head of Procurement Manangement Unit<\\/p>\",\"content_en\":\"<p>Acting Head of Procurement Manangement Unit<\\/p>\",\"photo_url\":\"48f48f4e780596d4a6b374f0ae10e6e3.png\",\"slug\":\"ag-hpmu\"}','2023-12-14 08:49:36','2023-12-14 08:49:36');
