,\"updated_at\":\"2023-12-14T10:14:09.000000Z\"}','2023-12-16 12:49:32','2023-12-16 12:49:32'),(1419,6,'Translation','trans_update','197.186.2.91','http://demo81.eganet.go.tz/tpsc/cms/trans_update','{\"id\":339,\"keyword\":\"lbl_more_short_courses\",\"en\":\"More Short Courses\",\"sw\":\"Tazama Kozi fupi zote\",\"created_at\":\"2023-11-06T17:14:24.000000Z\",\"updated_at\":\"2023-12-16T15:46:57.000000Z\"}','2023-12-16 12:49:32','2023-12-16 12:49:32'),(1420,6,'Translation','trans_update','197.186.2.91','http://demo81.eganet.go.tz/tpsc/cms/trans_update','{\"id\":340,\"keyword\":\"lbl_up_coming_short_courses\",\"en\":\"Up Coming Short Courses\",\"sw\":\"Mafunzo Mafupi yanayokaribia\",\"created_at\":\"2023-11-06T17:14:24.000000Z\",\"updated_at\":\"2023-12-15T13:16:55.000000Z\"}','2023-12-16 12:49:32','2023-12-16 12:49:32'),(1421,6,'Translation','trans_update','197.186.2.91','http://demo81.eganet.go.tz/tpsc/cms/trans_update','{\"id\":332,\"keyword\":\"lbl_medicine_purchase_summary\",\"en\":\"The procedure to purchase is simple, Depending on your location reach out to our Sales Personnel in your area.\",\"sw\":\"Utaratibu wa kununua ni rahisi, Kulingana na eneo lako wasiliana na Wafanyikazi wetu wa Uuzaji katika eneo lako.\",\"created_at\":\"2022-01-09T17:40:46.000000Z\",\"updated_at\":\"2022-01-09T14:42:44.000000Z\"}','2023-12-16 12:49:32','2023-12-16 12:49:32'),(1422,6,'Translation','trans_update','197.186.2.91','http://demo81.eganet.go.tz/tpsc/cms/trans_update','{\"id\":335,\"keyword\":\"lbl_courses\",\"en\":\"Courses\",\"sw\":\"Kozi\",\"created_at\":\"2022-01-05T12:11:00.000000Z\",\"updated_at\":\"2022-01-05T12:11:00.000000Z\"}','2023-12-16 12:49:32','2023-12-16 12:49:32'),(1423,6,'Translation','trans_update','197.186.2.91','http://demo81.eganet.go.tz/tpsc/cms/trans_update','{\"id\":334,\"keyword\":\"lbl_quotations\",\"en\":\"quotations\",\"sw\":\"nukuu\",\"created_at\":\"2022-01-04T15:27:00.000000Z\",\"updated_at\":\"2022-01-04T15:27:00.000000Z\"}','2023-12-16 12:49:32','2023-12-16 12:49:32'),(1424,6,'Translation','trans_update','197.186.2.91','http://demo81.eganet.go.tz/tpsc/cms/trans_update','{\"id\":333,\"keyword\":\"lbl_campuses\",\"en\":\"campuses\",\"sw\":\"Kampasi\",\"created_at\":\"2022-01-04T14:30:00.000000Z\",\"updated_at\":\"2022-01-04T14:30:00.000000Z\"}','2023-12-16 12:49:32','2023-12-16 12:49:32'),(1425,6,'Translation','trans_update','197.186.2.91','http://demo81.eganet.go.tz/tpsc/cms/trans_update','{\"id\":330,\"keyword\":\"lbl_medicine_purchase\",\"en\":\"Medicine Purchase\",\"sw\":\"Manunuzi ya Dawa\",\"created_at\":\"2021-11-23T17:03:17.000000Z\",\"updated_at\":\"2022-01-09T14:38:24.000000Z\"}','2023-12-16 12:49:32','2023-12-16 12:49:32'),(1426,6,'Translation','trans_update','197.186.2.91','http://demo81.eganet.go.tz/tpsc/cms/trans_update','{\"id\":344,\"keyword\":\"lbl_particulars\",\"en\":\"particulars\",\"sw\":\"Maelezo mafupi\",\"created_at\":\"2023-12-15T10:08:24.000000Z\",\"updated_at\":\"2023-12-15T10:08:24.000000Z\"}','2023-12-16 12:50:36','2023-12-16 12:50:36'),(1427,6,'Translation','trans_update','197.186.2.91','http://demo81.eganet.go.tz/tpsc/cms/trans_update','{\"id\":343,\"keyword\":\"lb_particulars\",\"en\":\"particulars\",\"sw\":\"Maelezo mafupi\",\"created_at\":\"2023-12-15T10:07:29.000000Z\",\"updated_at\":\"2023-12-15T10:07:29.000000Z\"}','2023-12-16 12:50:36','2023-12-16 12:50:36'),(1428,6,'Translation','trans_update','197.186.2.91','http://demo81.eganet.go.tz/tpsc/cms/trans_update','{\"id\":340,\"keyword\":\"lbl_up_coming_short_courses\",\"en\":\"Up Coming Short Courses\",\"sw\":\"Mafunzo Mafupi\",\"created_at\":\"2023-11-06T17:14:24.000000Z\",\"updated_at\":\"2023-12-16T15:49:32.000000Z\"}','2023-12-16 12:50:36','2023-12-16 12:50:36'),(1429,6,'Administration','update','41.222.177.112','http://demo81.eganet.go.tz/tpsc/cms/administration/12','{\"id\":12,\"salutation_en\":\"Mr\",\"salutation_sw\":\"Bw.\",\"fullname\":\"Shakiru Abdulkarim\",\"position\":\"0\",\"title_sw\":\"Mkuu wa Kitengo cha Mawasiliano na Masoko\",\"title_en\":\"Head of Communication and Marketing\",\"content_sw\":\"<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\"><span style=\\\"font-size:12.0pt\\\"><span style=\\\"color:#0070c0\\\">Shakiru Abdulkarim is a dynamic professional with nineteen years of extensive experience in the fields of corporate communication, marketing, and project management. Currently serving as the Head of Communication and Marketing responsible for planning, development, and implementation of college marketing strategies, communications, and public relations activities.<\\/span><\\/span><\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\"><span style=\\\"font-size:12.0pt\\\"><span style=\\\"color:#0070c0\\\">Shakiru has previously worked with Tanzania Global Learning Agency as Principal Marketing Officer, UTT Projects and Infrastructure Development PLC as Head of Project Management, Unit Trust of Tanzania as Principal Operations Offer, and<\\/span><\\/span> <span style=\\\"font-size:12.0pt\\\"><span style=\\\"color:#0070c0\\\">Tanzania Telecommunication Company Ltd as Customer Service officer. <\\/span><\\/span><\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\"><span style=\\\"font-size:12.0pt\\\"><span style=\\\"color:#0070c0\\\">With his strong background in communication, marketing, project management, and operations, Shakiru continues to make valuable contributions in driving success for the college and achieving remarkable results.<\\/span><\\/span><\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\"><span style=\\\"color:#0070c0\\\">He holds a Bachelor of Arts with horns and a Master of Business Administration in Marketing from the University of Dar es Salaam and Open University of Tanzania respectively.<\\/span><\\/span><\\/span><\\/p>\",\"content_en\":\"<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\">Shakiru Abdulkarim ni mtaalamu mwenye uzoefu wa miaka kumi na tisa katika nyanja za mawasiliano ya umma, masoko na usimamizi wa mradi. Kwa sasa anahudumu kama Mkuu wa Kitengo Mawasiliano na Masoko anayehusika na kupanga, kuendeleza na kutekeleza mikakati ya mawasiliano na masoko na kusimamia shughuli za mahusiano ya umma ya Chuo.<\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\">Kabla ya kujiunga na Chuo, Shakiru amewahi kufanya kazi na Wakala wa Mafunzo kwa Njia ya Mtandao (TaGLA) kama Afisa Mkuu wa Masoko, Taasisi ya Miradi na Maendeleo ya Miundombinu ya UTT ( UTT-PID) kama Msimamizi Mkuu wa Miradi, na Dhamana ya Uwekezaji Tanzania ( UTT) &nbsp;kama Afisa Mwendaji Mkuu na Kampuni ya Mawasiliano Tanzania (TTCL )kama Afisa Huduma kwa Wateja.<\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\">Akiwa na uzoefu mkubwa katika mawasiliano ya umma, Masoko, usimamizi wa miradi, na uendeshaji, Shakiru anaendelea kutoa mchango muhimu katika kuleta mafanikio kwa chou.<\\/span><\\/span><\\/p>\\r\\n\\r\\n<p><span style=\\\"font-size:11.0pt\\\"><span style=\\\"font-family:&quot;Calibri&quot;,sans-serif\\\">Shakiru ana Shahada ya Kwanza ya Sanaa na Shahada ya Uzamili ya Usimamizi &nbsp;wa Biashara katika Masoko kutoka Chuo Kikuu cha Dar es Salaam na Chuo Kikuu Huria cha Tanzania mtawalia.<\\/span><\\/span><\\/p>\",\"photo_url\":\"ae1c3a3259625c377d40269bd5704d76.png\",\"email\":\"abdulkarim.shakiru@tpsc.go.tz\",\"phone\":\"+2556542428\",\"created_at\":\"2023-12-14T11:31:59.000000Z\",\"updated_at\":\"2023-12-14T11:38:02.000000Z\",\"slug\":\"head-of-communication-and-marketinging\"}','2023-12-17 14:13:46','2023-12-17 14:13:46'),(1430,6,'Administration','update','41.222.177.112','http://demo81.eganet.go.tz/tpsc/cms/administration/12','{\"id\":12,\"salutation_en\":\"Mr\",\"salutation_sw\":\"Bw.\",\"fullname\":\"Shakiru Abdulkarim\",\"position\":\"0\",\"title_sw\":\"Mkuu wa Kitengo cha Mawasiliano na Masoko\",\"title_en\":\"Head of Communication and Marketing\",\"content_sw\":\"<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\"><span style=\\\"font-size:12.0pt\\\">Shakiru Abdulkarim is a dynamic professional with nineteen years of extensive experience in the fields of corporate communication, marketing, and project management. Currently serving as the Head of Communication and Marketing responsible for planning, development, and implementation of college marketing strategies, communications, and public relations activities.<\\/span><\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\"><span style=\\\"font-size:12.0pt\\\">Shakiru has previously worked with Tanzania Global Learning Agency as Principal Marketing Officer, UTT Projects and Infrastructure Development PLC as Head of Project Management, Unit Trust of Tanzania as Principal Operations Offer, and<\\/span> <span style=\\\"font-size:12.0pt\\\">Tanzania Telecommunication Company Ltd as Customer Service officer. <\\/span><\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\"><span style=\\\"font-size:12.0pt\\\">With his strong background in communication, marketing, project management, and operations, Shakiru continues to make valuable contributions in driving success for the college and achieving remarkable results.<\\/span><\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\">He holds a Bachelor of Arts with horns and a Master of Business Administration in Marketing from the University of Dar es Salaam and Open University of Tanzania respectively.<\\/span><\\/span><\\/p>\",\"content_en\":\"<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\">Shakiru Abdulkarim ni mtaalamu mwenye uzoefu wa miaka kumi na tisa katika nyanja za mawasiliano ya umma, masoko na usimamizi wa mradi. Kwa sasa anahudumu kama Mkuu wa Kitengo Mawasiliano na Masoko anayehusika na kupanga, kuendeleza na kutekeleza mikakati ya mawasiliano na masoko na kusimamia shughuli za mahusiano ya umma ya Chuo.<\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\">Kabla ya kujiunga na Chuo, Shakiru amewahi kufanya kazi na Wakala wa Mafunzo kwa Njia ya Mtandao (TaGLA) kama Afisa Mkuu wa Masoko, Taasisi ya Miradi na Maendeleo ya Miundombinu ya UTT ( UTT-PID) kama Msimamizi Mkuu wa Miradi, na Dhamana ya Uwekezaji Tanzania ( UTT) &nbsp;kama Afisa Mwendaji Mkuu na Kampuni ya Mawasiliano Tanzania (TTCL )kama Afisa Huduma kwa Wateja.<\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\">Akiwa na uzoefu mkubwa katika mawasiliano ya umma, Masoko, usimamizi wa miradi, na uendeshaji, Shakiru anaendelea kutoa mchango muhimu katika kuleta mafanikio kwa chou.<\\/span><\\/span><\\/p>\\r\\n\\r\\n<p><span style=\\\"font-size:11.0pt\\\">Shakiru ana Shahada ya Kwanza ya Sanaa na Shahada ya Uzamili ya Usimamizi &nbsp;wa Biashara katika Masoko kutoka Chuo Kikuu cha Dar es Salaam na Chuo Kikuu Huria cha Tanzania mtawalia.<\\/span><\\/p>\",\"photo_url\":\"ae1c3a3259625c377d40269bd5704d76.png\",\"email\":\"abdulkarim.shakiru@tpsc.go.tz\",\"phone\":\"+2556542428\",\"created_at\":\"2023-12-14T11:31:59.000000Z\",\"updated_at\":\"2023-12-17T17:13:46.000000Z\",\"slug\":\"head-of-communication-and-marketinging\"}','2023-12-17 14:16:25','2023-12-17 14:16:25'),(1431,6,'Administration','update','197.186.1.101','http://demo81.eganet.go.tz/tpsc/cms/administration/15','{\"id\":15,\"salutation_en\":\"Mr.\",\"salutation_sw\":\"Ndg.\",\"fullname\":\"Elibarick Mushi\",\"position\":\"0\",\"title_sw\":\"Kaimu Mkurugenzi - Huduma Wezeshi za Taaluma\",\"title_en\":\"Ag. Director - Academic Supports Services\",\"content_sw\":\"<p style=\\\"text-align:justify\\\">Bw. Elibarick Mushi aliteuliwa kushika nafasi ya Mkurugenzi wa huduma wezeshi za Taaluma (Kaimu) tangu mwezi Novemba 2023. Kabla ya nafasi hiyo, amepata fursa ya kutumikia katika nafasi mbalimbali katika Chuo cha Utumishi wa Umma Tanzania kama vile Kusimamia Kitengo cha Udhibiti\\/Uhakiki Ubora (Mwaka mmoja na nusu), Kusimamia Kitengo cha TEHAMA (Mwaka mmoja na nusu), Meneja Mafunzo (Miaka Minne), Mkuu wa Kitengo cha Usajili na Mitihani katika Kampasi (Miaka mitatu), na Mratibu wa TeHAMA katika Kampasi (Mwaka Mmoja). Kabla ya kujiunga na Chuo cha Utumishi wa Umma Tanzania, ametumika kama Mhadhiri Msaidizi, na Mhadhiri Mwandamizi katika chuo cha Kimataifa cha Kampala kwa kipindi cha miaka minne.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">Akiwa na Uzoefu wa Miaka 13 kwenye tasnia ya mafunzo katika vyuo, ikiambatana na dhamira ya dhati ya kutumia TEHAMA kuboresha utendaji kazi za taasisi, Elibarick amekuwa na mchango mkubwa katika kuibua vipaji vya kizazi kipya cha wataalamu wa TEHAMA pamoja na kuwahamasisha wanachuo wa fani nyingine kutumia vema TEHAMA katika kuongeza tija kwenye majukumu yao kazini. Maeneo yake ya Ubobevu kitaaluma ni Lugha za Computer, Mifumo Mtandao, Utengenezaji Mifumo, Uundaji wa Kanzidata, na Programu rahisishi za kazi za Ofisi.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">Mbali na kushiri katika kazi za taaluma,&nbsp; fursa aliyopata ya kutumika katika nafasi mbalimbali za uongozi na utawala zimempa uzoefu katika maeneo ya Utawala, Uundaji na Usimamizi wa Utekelezaji wa Mitaala ya vyuo, Uundaji wa Sera, Udhibiti\\/Uhakiki ubora wa Vyuo na Uratibu wa Kazi za kamati za taaluma vyuoni.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">Kielimu, Elibarick ana Shahada ya Kwanza ya Menejimenti ya Mifumo na Shahada ya Uzamili ya Mifumo.<\\/p>\",\"content_en\":\"<p style=\\\"text-align:justify\\\">Mr. Elibarick Mushi assumed the role of Director of Academic Support Services (Acting) in November 2023. Prior to his current position, he served in various key roles at Tanzania Public Service College, including Head of Quality Assurance (1.5 years), Head of ICT (1.5 years), Manager of Programmes (4 years), Campus Head of Admission and Examination Unit (3 years), and Campus ICT Coordinator (1 year). Before joining TPSC, he served for four years as an Assistant Lecturer and Tutorial Assistant at Kampala International University.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">With 13 years of dedicated experience in higher education, coupled with passion about utilizing technology to enhance business operations, Elibarick has played a pivotal role in shaping the next generation of ICT professionals and inspiring students from diverse fields to leverage ICT for improved performance in their respective professions. His training expertise spans computer programming, web applications development, Information Systems, database design, and office applications.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">In addition to his teaching roles, Elibarick&#39;s exposure to managerial and administrative duties has honed his skills in Administration, Curriculum Development and Implementation, Policy Formulation, Quality Assurance in Colleges, and Academic Committees&rsquo; Management.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">Elibarick holds a Bachelor&#39;s degree in Management Information Systems and a Master&#39;s degree in Information Systems.<\\/p>\",\"photo_url\":\"882fc34c01729e46b8ff8307fd754e2e.png\",\"email\":\"elibarick.mushi@tpsc.go.tz\",\"phone\":\"0753860432\",\"created_at\":\"2023-12-14T11:49:50.000000Z\",\"updated_at\":\"2023-12-16T15:24:49.000000Z\",\"slug\":\"director\"}','2023-12-18 09:57:06','2023-12-18 09:57:06'),(1432,6,'Administration','update','197.186.1.101','http://demo81.eganet.go.tz/tpsc/cms/administration/16','{\"id\":16,\"salutation_en\":\"Mr.\",\"salutation_sw\":\"Ndg.\",\"fullname\":\"Sijali Korojelo\",\"position\":\"0\",\"title_sw\":\"Mkurugenzi\",\"title_en\":\"Director\",\"content_sw\":\"<p style=\\\"text-align:justify\\\">Nulla fringilla imperdiet enim nec dictum. Aliquam semper sollicitudin urna, sed ornare est dignissim non. Nunc suscipit efficitur lorem sed rutrum. Nam odio orci, finibus in ullamcorper in, gravida ut ante. Donec sed justo porta, semper nibh non, rhoncus neque. Etiam vel est ut nunc fermentum ullamcorper. Sed dapibus tempus aliquam.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">Quisque vulputate lobortis consequat. Sed tincidunt a dui et dapibus. Duis at metus et ex viverra ullamcorper. Aenean eget eros lorem. Curabitur elementum tellus eget condimentum feugiat. Proin blandit lobortis neque at mattis. Fusce mollis sem elit, eu ullamcorper ex auctor a. Sed posuere tristique libero sit amet ornare. Quisque eu ullamcorper turpis. Praesent tristique pharetra quam, id dapibus turpis viverra sed.<\\/p>\",\"content_en\":\"<p style=\\\"text-align:justify\\\">Nulla fringilla imperdiet enim nec dictum. Aliquam semper sollicitudin urna, sed ornare est dignissim non. Nunc suscipit efficitur lorem sed rutrum. Nam odio orci, finibus in ullamcorper in, gravida ut ante. Donec sed justo porta, semper nibh non, rhoncus neque. Etiam vel est ut nunc fermentum ullamcorper. Sed dapibus tempus aliquam.<\\/p>\\r\\n\\r\\n<p style=\\\"text-