000000Z\",\"slug\":\"campus-director-dar-es-salaam\"}','2023-12-19 08:20:29','2023-12-19 08:20:29'),(1469,6,'Administration','store','41.59.251.78','http://demo81.eganet.go.tz/tpsc/cms/administration','{\"salutation_sw\":\"CPA\",\"salutation_en\":\"CPA\",\"fullname\":\"Freddy George Chuwa\",\"title_sw\":\"Mkuu wa Kitengo cha Ukaguzi wa Ndani\",\"title_en\":\"Head of Internal Audit\",\"email\":\"freddy.chuwa@tpsc.go.tz\",\"phone\":\"+255 22 2152982\",\"position\":\"0\",\"content_sw\":null,\"content_en\":null,\"photo_url\":\"2b292353b8b5bc4bec63e48c616ff746.jpeg\",\"slug\":\"head-of-internal-audit\"}','2023-12-19 08:30:00','2023-12-19 08:30:00'),(1470,6,'AdministrationCategoriesMembers','store','41.59.251.78','http://demo81.eganet.go.tz/tpsc/cms/administration_categories_members','{\"member_id\":\"34\",\"title_en\":\"Head of Internal Audit\",\"title_sw\":\"Mkuu wa Kitengo cha Ukaguzi wa Ndani\",\"position\":\"4\",\"category_id\":\"5\"}','2023-12-19 08:31:06','2023-12-19 08:31:06'),(1471,6,'AdministrationCategoriesMembers','update','41.59.251.78','http://demo81.eganet.go.tz/tpsc/cms/administration_categories_members/31','{\"id\":31,\"category_id\":\"5\",\"member_id\":\"34\",\"title_en\":\"Head of Internal Audit\",\"title_sw\":\"Mkuu wa Kitengo cha Ukaguzi wa Ndani\",\"parent\":0,\"position\":\"5\",\"created_at\":\"2023-12-19T11:31:06.000000Z\",\"updated_at\":\"2023-12-19T11:31:06.000000Z\"}','2023-12-19 08:31:48','2023-12-19 08:31:48'),(1472,6,'Administration','update','41.59.251.78','http://demo81.eganet.go.tz/tpsc/cms/administration/24','{\"id\":24,\"salutation_en\":\"Ms.\",\"salutation_sw\":\"Bi.\",\"fullname\":\"Zena  Hussein\",\"position\":\"0\",\"title_sw\":\"Kaimu Meneja - Sehemu ya  Mafunzo kwa Njia ya Mtandao\",\"title_en\":\"Ag.Manager - Global Learning Section\",\"content_sw\":null,\"content_en\":null,\"photo_url\":\"6f9c156c3740093e03540ddb5e771102.png\",\"email\":\"zena.hussein@tpsc.go.tz\",\"phone\":\"+255 22 2152982\",\"created_at\":\"2023-12-14T12:15:45.000000Z\",\"updated_at\":\"2023-12-14T12:50:35.000000Z\",\"slug\":\"manager-global-learning-section\"}','2023-12-19 08:33:27','2023-12-19 08:33:27'),(1473,6,'AdministrationCategoriesMembers','update','41.59.251.78','http://demo81.eganet.go.tz/tpsc/cms/administration_categories_members/21','{\"id\":21,\"category_id\":\"5\",\"member_id\":\"24\",\"title_en\":\"Ag.Manager - Global Learning Section\",\"title_sw\":\"Kaimu Meneja - Kituo cha Mafunzo kwa Njia ya Mtandao\",\"parent\":0,\"position\":\"4\",\"created_at\":\"2023-12-14T12:44:47.000000Z\",\"updated_at\":\"2023-12-14T12:44:47.000000Z\"}','2023-12-19 08:33:57','2023-12-19 08:33:57'),(1474,6,'Page','update','41.59.251.78','http://demo81.eganet.go.tz/tpsc/cms/pages/8','{\"id\":8,\"title_sw\":\"Historia\",\"title_en\":\"Historical Background\",\"has_sidebar\":\"1\",\"content_sw\":\"<p style=\\\"text-align:justify\\\">Chuo cha Utumishi wa Umma Tanzania (TPSC) kilianzishwa mwaka 2000 kwa sheria ya Wakala za Serikali Na. 30 ya mwaka 1997. Lengo la kuanzishwa kwake lilikuwa kuziba pengo la kuwa na taasisi ya mafunzo jumuishi kwa utumishi wa umma kukidhi mahitaji yanayobadilika ya utumishi wa umma yaliyosababishwa na maboresho ya utumishi wa umma na haja ya kuwa na chuo cha utumishi wa umma kinachojitegemea chenye uwezo wa fedha endelevu.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">Kutokana na hali hiyo, TPSC ni mtoa huduma ya maarifa na stadi anayependelewa kwa utumishi wa umma katika maeneo ya uongozi, Usimamizi wa Kimkakati, Utawala, maadili na uwajibika. Pia ni taasisi ya kujenga utamaduni wa elimu endelevu kwa watumishi wa umma. Wateja wa TPSC ni pamoja na Serikali Kuu na <a href=\\\"http:\\/\\/demo81.eganet.go.tz\\/tpsc\\/uploads\\/text-editor\\/files\\/sw-1700917512-KARUME BOYS_1702468256.pdf\\\" target=\\\"_blank\\\">Serikali za Mitaa<\\/a>, idara zinzojitegemea, Wakala za Serikali, wanaohitimu elimu ya Sekondari, umma kwa jumla na sekta binafsi.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">TPSC ina Kampasi sita zilizojengwa kimkakati jijini&nbsp;<strong>Dar es Salaam, Tabora,&nbsp;<\\/strong><strong>Mtwara,&nbsp;<\\/strong><strong>Singida, Tanga na<\\/strong>&nbsp;<strong>Mbeya<\\/strong>&nbsp;pamoja na&nbsp;<strong>K<\\/strong>ituo cha kutoa&nbsp;<strong>Mafunzo kwa njia ya Mtandao<\\/strong>&nbsp;ili iwe karibu na wateja wake nchi nzima.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">Taasisi inatoa masomo katika viwango vitatu vya Cheti (Basic Technician Certificate), Diploma na Shahada ya Kwanza (BA) myanayofaa kwa sekta ya umma na binafsi katika Kampasi zake.Licha ya Programu hizo, TPSCinatoa masomo ya mapitio kwa ajili ya Mitihani ya Utumishi wa Umma na Huduma za Ushauri.Hivi karibuni imeanza ktumika mtindo wa Elimu na Mafunzo yanayotokana na Weledi. (CBET) kama njia ya maendeleo, namna ya kupata Elimu bora na Mafunzo yanayokidhi mahitaji ya soko la ajira la kudumu na linalo haraka sana.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">&nbsp;<\\/p>\",\"content_en\":\"<p style=\\\"text-align:justify\\\">The Tanzania Public Service College (TPSC) is a Technical Institutions in Tanzania was established in 2000 under the ambit of the Executive Agencies Act No 30 of 1997. The aim of it&rsquo;s establishment was to fill an extant void in terms of a comprehensive training facility for Public Service, to meet the changing needs of the Public Services resulted from the Public Service Reforms, and the need for an autonomous financially sustainable public service College.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">It is in light of the above that the TPSC is the preferred service provider of knowledge and skills to the public service, but also as a part of building a culture of continuous learning for public servants. The customers of TPSC include; central and <a href=\\\"http:\\/\\/demo81.eganet.go.tz\\/tpsc\\/uploads\\/text-editor\\/files\\/sw-1700917512-KARUME BOYS_1702468256.pdf\\\" target=\\\"_blank\\\">local government<\\/a>, independent departments, executive agencies; secondary school leavers, the general public and<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">TPSC has&nbsp;<strong>Six Campuses&nbsp;<\\/strong>strategically located in&nbsp;<strong>Dar es Salaam<\\/strong><strong>, Tabora, Mtwara, Singida, Tanga, Mbeya and One Global Learning Center&nbsp;<\\/strong>to be close to its customers countrywide<strong>.<\\/strong><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">The Institute is offering Basic Technician Certificate, Diploma, and Bachelor Degree Programmes suitable for public and private sectors in its campuses. Besides these programmes, TPSC is offering review classes for Public Service Examinations and consultancy services. It has recently adopted the Competence-Based Education and Training (CBET) approach as the way forward, the way to attain the quality of education and training that meets the demands of a dynamic and permanently changing labour market.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">&nbsp;<\\/p>\",\"slug\":\"historical-background\",\"status\":1,\"created_at\":\"2023-12-13T11:30:58.000000Z\",\"updated_at\":\"2023-12-13T11:54:17.000000Z\"}','2023-12-19 08:43:10','2023-12-19 08:43:10'),(1475,6,'PressRelease','destroy','41.59.251.78','http://demo81.eganet.go.tz/tpsc/cms/press_releases/4','{\"id\":4,\"name_sw\":\"Mapitio Ya Kikao Kazi Cha Utendaji Wa TNBC\\u00a0\",\"name_en\":\"Mapitio Ya Kikao Kazi Cha Utendaji Wa TNBC\\u00a0\",\"content_sw\":\"<p>Mapitio Ya Kikao Kazi Cha Utendaji Wa TNBC&nbsp;&nbsp;Mapitio Ya Kikao Kazi Cha Utendaji Wa TNBC&nbsp;Mapitio Ya Kikao Kazi Cha Utendaji Wa TNBC&nbsp;Mapitio Ya Kikao Kazi Cha Utendaji Wa TNBC&nbsp;Mapitio Ya Kikao Kazi Cha Utendaji Wa TNBC&nbsp;Mapitio Ya Kikao Kazi Cha Utendaji Wa TNBC&nbsp;Mapitio Ya Kikao Kazi Cha Utendaji Wa TNBC&nbsp;Mapitio Ya Kikao Kazi Cha Utendaji Wa TNBC&nbsp;<\\/p>\",\"content_en\":\"<p>Mapitio Ya Kikao Kazi Cha Utendaji Wa TNBC&nbsp;Mapitio Ya Kikao Kazi Cha Utendaji Wa TNBC&nbsp;Mapitio Ya Kikao Kazi Cha Utendaji Wa TNBC&nbsp;Mapitio Ya Kikao Kazi Cha Utendaji Wa TNBC&nbsp;Mapitio Ya Kikao Kazi Cha Utendaji Wa TNBC&nbsp;Mapitio Ya Kikao Kazi Cha Utendaji Wa TNBC&nbsp;Mapitio Ya Kikao Kazi Cha Utendaji Wa TNBC&nbsp;Mapitio Ya Kikao Kazi Cha Utendaji Wa TNBC&nbsp;Mapitio Ya Kikao Kazi Cha Utendaji Wa TNBC&nbsp;Mapitio Ya Kikao Kazi Cha Utendaji Wa TNBC&nbsp;Mapitio Ya Kikao Kazi Cha Utendaji Wa TNBC&nbsp;<\\/p>\",\"file_en\":\"\\/uploads\\/press_releases\\/en1627887240-INSTITUTE OF CONSTRUCTION TECHNOLOGY Website.docx\",\"file_sw\":\"\\/uploads\\/press_releases\\/sw1627887240-INSTITUTE OF CONSTRUCTION TECHNOLOGY Website.docx\",\"active\":1,\"slug\":\"mapitio-ya-kikao-kazi-cha-utendaji-wa-tnbc\",\"user_id\":1,\"created_at\":\"2021-08-02T06:54:00.000000Z\",\"updated_at\":\"2021-08-02T06:54:00.000000Z\"}','2023-12-19 08:48:07','2023-12-19 08:48:07'),(1476,6,'Announcement','destroy','41.59.251.78','http://demo81.eganet.go.tz/tpsc/cms/announcements/9','{\"id\":9,\"name_sw\":\"Tangazo la Kazi (Afisa TEHAMA Daraja la II)\",\"name_en\":\"Job Advert (ICT Officer II)\",\"content_sw\":\"<p style=\\\"text-align: justify;\\\">Nullam porta dapibus arcu id feugiat. Duis pharetra ornare urna, sed varius lorem consequat euismod. Etiam quis ex laoreet, ultricies mauris nec, congue eros. Nulla tellus sapien, pharetra in hendrerit nec, condimentum ac tortor. In efficitur tortor vel nulla auctor, vitae porttitor tellus porttitor. Quisque vitae turpis non velit accumsan varius sed in magna. Proin a quam pretium, facilisis ex quis, scelerisque leo. Etiam faucibus mi ac elit facilisis, eget molestie arcu efficitur. Etiam vitae urna dignissim, sagittis felis sit amet, volutpat tortor. Phasellus lobortis rhoncus risus, ut tincidunt ligula placerat vitae. Sed odio ligula, accumsan sit amet sollicitudin sit amet, pellentesque convallis tellus. Pellentesque quis urna lectus. Morbi ut nulla justo. Nunc feugiat interdum cursus. Donec nec felis non neque convallis dapibus.<\\/p>\",\"content_en\":\"<p style=\\\"text-align: justify;\\\">Nullam porta dapibus arcu id feugiat. Duis pharetra ornare urna, sed varius lorem consequat euismod. Etiam quis ex laoreet, ultricies mauris nec, congue eros. Nulla tellus sapien, pharetra in hendrerit nec, condimentum ac tortor. In efficitur tortor vel nulla auctor, vitae porttitor tellus porttitor. Quisque vitae turpis non velit accumsan varius sed in magna. Proin a quam pretium, facilisis ex quis, scelerisque leo. Etiam faucibus mi ac elit facilisis, eget molestie arcu efficitur. Etiam vitae urna dignissim, sagittis felis sit amet, volutpat tortor. Phasellus lobortis rhoncus risus, ut tincidunt ligula placerat vitae. Sed odio ligula, accumsan sit amet sollicitudin sit amet, pellentesque convallis tellus. Pellentesque quis urna lectus. Morbi ut nulla justo. Nunc feugiat interdum cursus. Donec nec felis non neque convallis dapibus.<\\/p>\",\"active\":1,\"slug\":\"job-advert-ict-officer-ii\",\"created_at\":\"2023-12-15T12:23:37.000000Z\",\"updated_at\":\"2023-12-15T12:23:37.000000Z\"}','2023-12-19 08:48:25','2023-12-19 08:48:25'),(1477,6,'Administration','update','154.118.226.162','http://demo81.eganet.go.tz/tpsc/cms/administration/12','{\"id\":12,\"salutation_en\":\"Mr\",\"salutation_sw\":\"Bw.\",\"fullname\":\"Shakiru Abdulkarim\",\"position\":\"0\",\"title_sw\":\"Mkuu wa Kitengo cha Mawasiliano na Masoko\",\"title_en\":\"Head of Communication and Marketing\",\"content_sw\":\"<p style=\\\"text-align:justify\\\">--<\\/p>\",\"content_en\":\"<p style=\\\"text-align:justify\\\">--<\\/p>\",\"photo_url\":\"94e56ab29dd3a01be6ba6a0b4c7ffbdb.jpeg\",\"email\":\"abdulkarim.shakiru@tpsc.go.tz\",\"phone\":\"+2556542428\",\"created_at\":\"2023-12-14T11:31:59.000000Z\",\"updated_at\":\"2023-12-19T11:01:23.000000Z\",\"slug\":\"head-of-communication-and-marketinging\"}','2023-12-19 08:51:08','2023-12-19 08:51:08'),(1478,6,'Administration','update','154.118.226.162','http://demo81.eganet.go.tz/tpsc/cms/administration/12','{\"id\":12,\"salutation_en\":\"Mr\",\"salutation_sw\":\"Bw.\",\"fullname\":\"Shakiru Abdulkarim\",\"position\":\"0\",\"title_sw\":\"Mkuu wa Kitengo cha Mawasiliano na Masoko\",\"title_en\":\"Head of Communication and Marketing\",\"content_sw\":\"<p style=\\\"text-align: justify;\\\">Shakiru Abdulkarim ni mtaalamu mwenye uzoefu wa miaka kumi na tisa katika nyanja za mawasiliano ya umma, masoko na usimamizi wa mradi. Kwa sasa anahudumu kama Mkuu wa Kitengo Mawasiliano na Masoko anayehusika na kupanga, kuendeleza na kutekeleza mikakati ya mawasiliano na masoko na kusimamia shughuli za mahusiano ya umma ya Chuo.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align: justify;\\\">Kabla ya kujiunga na Chuo, Shakiru amewahi kufanya kazi na Wakala wa Mafunzo kwa Njia ya Mtandao (TaGLA) kama Afisa Mkuu wa Masoko, Taasisi ya Miradi na Maendeleo ya Miundombinu ya UTT ( UTT-PID) kama Msimamizi Mkuu wa Miradi, na Dhamana ya Uwekezaji Tanzania ( UTT) &nbsp;kama Afisa Mwendaji Mkuu na Kampuni ya Mawasiliano Tanzania (TTCL )kama Afisa Huduma kwa Wateja.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align: justify;\\\">Akiwa na uzoefu mkubwa katika mawasiliano ya umma, Masoko, usimamizi wa miradi, na uendeshaji, Shakiru anaendelea kutoa mchango muhimu katika kuleta mafanikio kwa chou.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align: justify;\\\">Shakiru ana Shahada ya Kwanza ya Sanaa na Shahada ya Uzamili ya Usimamizi &nbsp;wa Biashara katika Masoko kutoka Chuo Kikuu cha Dar es Salaam na Chuo Kikuu Huria cha Tanzania mtawalia.<\\/p>\",\"content_en\":\"<p style=\\\"text-align: justify;\\\">Shakiru Abdulkarim is a dynamic professional with nineteen years of extensive experience in the fields of corporate communication, marketing, and project management. Currently serving as the Head of Communication and Marketing responsible for planning, development, and implementation of college marketing strategies, communications, and public relations activities.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align: justify;\\\">Shakiru has previously worked with Tanzania Global Learning Agency as Principal Marketing Officer, UTT Projects and Infrastructure Development PLC as Head of Project Management, Unit Trust of Tanzania as Principal Operations Offer, and Tanzania Telecommunication Company Ltd as Customer Service officer.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align: justify;\\\">With his strong background in communication, marketing, project management, and operations, Shakiru continues to make valuable contributions in driving success for the college and achieving remarkable results.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align: justify;\\\">He holds a Bachelor of Arts with horns and a Master of Business Administration in Marketing from the University of Dar es Salaam and Open University of Tanzania respectively.<\\/p>\",\"photo_url\":\"94e56ab29dd3a01be6ba6a0b4c7ffbdb.jpeg\",\"email\":\"abdulkarim.shakiru@tpsc.go.tz\",\"phone\":\"+2556542428\",\"created_at\":\"2023-12-14T11:31:59.000000Z\",\"updated_at\":\"2023-12-19T11:51:08.000000Z\",\"slug\":\"head-of-communication-and-marketinging\"}','2023-12-19 08:51:54','2023-12-19 08:51:54'),(1479,6,'Documents','store','41.59.251.78','http://demo81.eganet.go.tz/tpsc/cms/documents','{\"title_sw\":\"Waziri Simbachawene awaonya Watumishi kuwadharau Wananchi\",\"title_en\":\"Waziri Simbachawene awaonya Watumishi kuwadharau Wananchi\",\"category_id\":\"16\",\"active\":\"1\",\"published_date\":\"2023-12-19\",\"file_sw\":\"sw-1702987822-MAKALA.pdf\",\"file_en\":\"en-1702987822-MAKALA.pdf\"}','2023-12-19 09:10:22','2023-12-19 09:10:22'),(1480,6,'Page','store','41.59.251.78','http://demo81.eganet.go.tz/tpsc/cms/pages','{\"title_en\":\"PUBLIC SERVICE EXAMINATIONS\",\"title_sw\":\"MITIHANI YA UTUMISHI WA UMMA\",\"has_sidebar\":\"0\",\"content_en\":\"<p>Public Service Examinations (PSE) and review programmes are primarily provided for public servants who are obliged by their respective schemes of service to undertake to enable them to meet certain criteria for their promotions.<\\/p>\\r\\n\\r\\n<p>List of the Examinations to be conducted:<\\/p>\\r\\n\\r\\n<p><br \\/>\\r\\n1. Higher Standard Government Accounting (HSGA)<br \\/>\\r\\n2. Higher Standard Stores Management (HSSM)<br \\/>\\r\\n3. Qualifying Law for Administrative Officers (QLA)<br \\/>\\r\\n4. Qualifying Law for Division Officers (QLD)<br \\/>\\r\\n5. Proficiency Examinations for Labour Officers (PLO)<br \\/>\\r\\n6. Proficiency Examinations for Social Welfare Officers (PSW)<br \\/>\\r\\n7. Proficiency Examinations for Human Resource Officers (PHR)<br \\/>\\r\\n8. Proficiency Examinations for Records Officers (PRO)<br \\/>\\r\\n9. Higher Standard Records Management (HSRM)<br \\/>\\r\\n10. Auditors Qualifying Examinations (AQE)<br \\/>\\r\\n11. Higher Standard Telephone Operators (HSTO)<br \\/>\\r\\n12. Kiswahili Kigumu (KK)<br \\/>\\r\\n13. Management Development for Executive Assistant (MDEA I &amp; II)<br \\/>\\r\\n14. Special Youth Work Examination (SYWE)<\\/p>\",\"content_sw\":\"<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:12pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\">Mitihani ya Utumishi wa Umma kwa watumishi wa umma ilianzishwa kwa mujibu wa kifungu cha (I) cha Kanuni za Kudumu za Utumishi wa Umma. Pia Sheria ya Utumishi wa Umma namba 8 ya mwaka 2002 iliyofanyiwa marekebisho mwaka 2008 ilitoa mamlaka kwa Chuo cha Utumishi wa Umma kuendesha hiyo tangu mwaka 2003. <\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:12pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\">Mitihani ya utumishi wa Umma hufanyika mara mbili kwa mwaka (Februari na Agosti) kwa muda wa wiki nne. Wiki tatu za kwanza ni za &nbsp;darasa la mapitio (review&nbsp; classes) na wiki moja ya mwisho ni kwa ajili ya watumishi kufanya mitihani yenyewe. <\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:12pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\">Mitihani ya utumishi wa umma inajumuisha:<\\/span><\\/span><\\/p>\\r\\n\\r\\n<ol>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\">Usimamizi wa Nyaraka kwa Wasaidizi wa Kumbukumbu&nbsp; (Higher Standard Records Management)<\\/span><\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\">Mtihani wa Waendeshaji Simu (Telephone Operators);<\\/span><\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\">Maendeleo ya Usimamizi kwa Wasaidizi wa Watendaji Wakuu I;<\\/span><\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\">Maendeleo ya Usimamizi kwa Wasaidizi wa Watendaji Wakuu II;<\\/span><\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\">Mtihani wa Umahiri kwa Maafisa Rasilimali Watu;<\\/span><\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\">Mtihani wa Umahiri kwa Maafisa Kumbukumbu;<\\/span><\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\">Mtihani wa Umahiri kwa Maafisa Ustawi wa Jamii<\\/span><\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\">Mtihani wa Umahiri kwa Maafisa Kazi;<\\/span><\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\">Sheria kwa Maafisa Tawala;<\\/span><\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\">Sheria kwa Maafisa Watendaji wa Kata\\/Tarafa; na<\\/span><\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\">Mtihani wa umahiri kwa Maafisa Maendeleo wa vijana;<\\/span><\\/span><\\/li>\\r\\n<\\/ol>\",\"slug\":\"public-service-examinations\"}','2023-12-19 09:31:22','2023-12-19 09:31:22'),(1481,6,'Page','update','41.59.251.78','http://demo81.eganet.go.tz/tpsc/cms/pages/13','{\"id\":13,\"title_sw\":\"Mitihani ya Utumishi wa Umma ( PSE)\",\"title_en\":\"Public Service Examinations\",\"has_sidebar\":\"0\",\"content_sw\":\"<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:12pt\\\">Mitihani ya Utumishi wa Umma kwa watumishi wa umma ilianzishwa kwa mujibu wa kifungu cha (I) cha Kanuni za Kudumu za Utumishi wa Umma. Pia Sheria ya Utumishi wa Umma namba 8 ya mwaka 2002 iliyofanyiwa marekebisho mwaka 2008 ilitoa mamlaka kwa Chuo cha Utumishi wa Umma kuendesha hiyo tangu mwaka 2003. <\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:12pt\\\">Mitihani ya utumishi wa Umma hufanyika mara mbili kwa mwaka (Februari na Agosti) kwa muda wa wiki nne. Wiki tatu za kwanza ni za &nbsp;darasa la mapitio (review&nbsp; classes) na wiki moja ya mwisho ni kwa ajili ya watumishi kufanya mitihani yenyewe. <\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:12pt\\\">Mitihani ya utumishi wa umma inajumuisha:<\\/span><\\/p>\\r\\n\\r\\n<ol>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\">Usimamizi wa Nyaraka kwa Wasaidizi wa Kumbukumbu&nbsp; (Higher Standard Records Management)<\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\">Mtihani wa Waendeshaji Simu (Telephone Operators);<\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\">Maendeleo ya Usimamizi kwa Wasaidizi wa Watendaji Wakuu I;<\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\">Maendeleo ya Usimamizi kwa Wasaidizi wa Watendaji Wakuu II;<\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\">Mtihani wa Umahiri kwa Maafisa Rasilimali Watu;<\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\">Mtihani wa Umahiri kwa Maafisa Kumbukumbu;<\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\">Mtihani wa Umahiri kwa Maafisa Ustawi wa Jamii<\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\">Mtihani wa Umahiri kwa Maafisa Kazi;<\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\">Sheria kwa Maafisa Tawala;<\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\">Sheria kwa Maafisa Watendaji wa Kata\\/Tarafa; na<\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\">Mtihani wa umahiri kwa Maafisa Maendeleo wa vijana;<\\/span><\\/li>\\r\\n<\\/ol>\",\"content_en\":\"<p>Public Service Examinations (PSE) and review programmes are primarily provided for public servants who are obliged by their respective schemes of service to undertake to enable them to meet certain criteria for their promotions.<\\/p>\\r\\n\\r\\n<p>List of the Examinations to be conducted:<\\/p>\\r\\n\\r\\n<p><br \\/>\\r\\n1. Higher Standard Government Accounting (HSGA)<br \\/>\\r\\n2. Higher Standard Stores Management (HSSM)<br \\/>\\r\\n3. Qualifying Law for Administrative Officers (QLA)<br \\/>\\r\\n4. Qualifying Law for Division Officers (QLD)<br \\/>\\r\\n5. Proficiency Examinations for Labour Officers (PLO)<br \\/>\\r\\n6. Proficiency Examinations for Social Welfare Officers (PSW)<br \\/>\\r\\n7. Proficiency Examinations for Human Resource Officers (PHR)<br \\/>\\r\\n8. Proficiency Examinations for Records Officers (PRO)<br \\/>\\r\\n9. Higher Standard Records Management (HSRM)<br \\/>\\r\\n10. Auditors Qualifying Examinations (AQE)<br \\/>\\r\\n11. Higher Standard Telephone Operators (HSTO)<br \\/>\\r\\n12. Kiswahili Kigumu (KK)<br \\/>\\r\\n13. Management Development for Executive Assistant (MDEA I &amp; II)<br \\/>\\r\\n14. Special Youth Work Examination (SYWE)<\\/p>\",\"slug\":\"public-service-examinations\",\"status\":1,\"created_at\":\"2023-12-19T12:31:22.000000Z\",\"updated_at\":\"2023-12-19T12:31:22.000000Z\"}','2023-12-19 09:33:11','2023-12-19 09:33:11'),(1482,6,'MenuItem','update','41.59.251.78','http://demo81.eganet.go.tz/tpsc/cms/menu-items/97','{\"id\":97,\"title_sw\":\"Mitihani ya Utumishi wa Umma\",\"title_en\":\"Public Service Examinations (PSE)\",\"status\":1,\"menu_id\":\"12\",\"url\":\"pages\\/public-service-examinations\",\"url_external\":null,\"link\":\"1\",\"parent\":87,\"position\":3,\"has_sidebar\":0,\"created_at\":\"2023-12-13T10:09:29.000000Z\",\"updated_at\":\"2023-12-15T16:17:07.000000Z\"}','2023-12-19 09:33:34','2023-12-19 09:33:34'),(1483,6,'Page','update','41.59.251.78','http://demo81.eganet.go.tz/tpsc/cms/pages/13','{\"id\":13,\"title_sw\":\"Mitihani ya Utumishi wa Umma ( PSE)\",\"title_en\":\"Public Service Examinations\",\"has_sidebar\":\"0\",\"content_sw\":\"<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:12pt\\\">Mitihani ya Utumishi wa Umma kwa watumishi wa umma ilianzishwa kwa mujibu wa kifungu cha (I) cha Kanuni za Kudumu za Utumishi wa Umma. Pia Sheria ya Utumishi wa Umma namba 8 ya mwaka 2002 iliyofanyiwa marekebisho mwaka 2008 ilitoa mamlaka kwa Chuo cha Utumishi wa Umma kuendesha hiyo tangu mwaka 2003. <\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:12pt\\\">Mitihani ya utumishi wa Umma hufanyika mara mbili kwa mwaka (Februari na Agosti) kwa muda wa wiki nne. Wiki tatu za kwanza ni za &nbsp;darasa la mapitio (review&nbsp; classes) na wiki moja ya mwisho ni kwa ajili ya watumishi kufanya mitihani yenyewe. <\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:12pt\\\">Kada zinazohusika na mitihani ya utumishi wa umma na programu za mapitio ni pamoja na:<\\/span><\\/p>\\r\\n\\r\\n<ol>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\">Usimamizi wa Nyaraka kwa Wasaidizi wa Kumbukumbu&nbsp; (Higher Standard Records Management)<\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\">Mtihani wa Waendeshaji Simu (Telephone Operators);<\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\">Maendeleo ya Usimamizi kwa Wasaidizi wa Watendaji Wakuu I;<\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\">Maendeleo ya Usimamizi kwa Wasaidizi wa Watendaji Wakuu II;<\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\">Mtihani wa Umahiri kwa Maafisa Rasilimali Watu;<\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\">Mtihani wa Umahiri kwa Maafisa Kumbukumbu;<\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\">Mtihani wa Umahiri kwa Maafisa Ustawi wa Jamii<\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\">Mtihani wa Umahiri kwa Maafisa Kazi;<\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\">Sheria kwa Maafisa Tawala;<\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\">Sheria kwa Maafisa Watendaji wa Kata\\/Tarafa; na<\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\">Mtihani wa umahiri kwa Maafisa Maendeleo wa vijana;<\\/span><\\/li>\\r\\n<\\/ol>\",\"content_en\":\"<p style=\\\"text-align: justify;\\\">Tanzania Public Service College has been administering Public Service Examinations and review programmes since 2003. Circular letter number<br \\/>\\r\\nC\\/CB.49\\/177\\/01A\\/46 dated 13th January, 2003 in line with the current Public Service Act No. 8 of 2002 as amended in 2008 mandated the Tanzania PublicService College to run the Public Service Examinations which were formallyrun by the Public Service Commission (PSC). Public Service Examinations(PSE) and review programmes are primarily provided for public servantswho are obliged by their respective schemes of service to undertake toenable them meet certain criteria for their promotions.<\\/p>\\r\\n\\r\\n<p>Cadres that are covered by public service examinations and review programmes include: -<\\/p>\\r\\n\\r\\n<p><br \\/>\\r\\n1. Higher Standard Government Accounting (HSGA)<br \\/>\\r\\n2. Higher Standard Stores Management (HSSM)<br \\/>\\r\\n3. Qualifying Law for Administrative Officers (QLA)<br \\/>\\r\\n4. Qualifying Law for Division Officers (QLD)<br \\/>\\r\\n5. Proficiency Examinations for Labour Officers (PLO)<br \\/>\\r\\n6. Proficiency Examinations for Social Welfare Officers (PSW)<br \\/>\\r\\n7. Proficiency Examinations for Human Resource Officers (PHR)<br \\/>\\r\\n8. Proficiency Examinations for Records Officers (PRO)<br \\/>\\r\\n9. Higher Standard Records Management (HSRM)<br \\/>\\r\\n10. Auditors Qualifying Examinations (AQE)<br \\/>\\r\\n11. Higher Standard Telephone Operators (HSTO)<br \\/>\\r\\n12. Kiswahili Kigumu (KK)<br \\/>\\r\\n13. Management Development for Executive Assistant (MDEA I &amp; II)<br \\/>\\r\\n14. Special Youth Work Examination (SYWE)<\\/p>\",\"slug\":\"public-service-examinations\",\"status\":1,\"created_at\":\"2023-12-19T12:31:22.000000Z\",\"updated_at\":\"2023-12-19T12:33:11.000000Z\"}','2023-12-19 09:39:33','2023-12-19 09:39:33'),(1484,6,'Page','update','41.59.251.78','http://demo81.eganet.go.tz/tpsc/cms/pages/13','{\"id\":13,\"title_sw\":\"Mitihani ya Utumishi wa Umma ( PSE)\",\"title_en\":\"Public Service Examinations\",\"has_sidebar\":\"0\",\"content_sw\":\"<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:12pt\\\">Mitihani ya Utumishi wa Umma kwa watumishi wa umma ilianzishwa kwa mujibu wa kifungu cha (I) cha Kanuni za Kudumu za Utumishi wa Umma. Pia Sheria ya Utumishi wa Umma namba 8 ya mwaka 2002 iliyofanyiwa marekebisho mwaka 2008 ilitoa mamlaka kwa Chuo cha Utumishi wa Umma kuendesha hiyo tangu mwaka 2003. <\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:12pt\\\">Mitihani ya utumishi wa Umma hufanyika mara mbili kwa mwaka (Februari na Agosti) kwa muda wa wiki nne. Wiki tatu za kwanza ni za &nbsp;darasa la mapitio (review&nbsp; classes) na wiki moja ya mwisho ni kwa ajili ya watumishi kufanya mitihani yenyewe. <\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:12pt\\\">Kada zinazohusika na mitihani ya utumishi wa umma na programu za mapitio ni pamoja na:<\\/span><\\/p>\\r\\n\\r\\n<ol>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\">Usimamizi wa Nyaraka kwa Wasaidizi wa Kumbukumbu&nbsp; (Higher Standard Records Management)<\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\">Mtihani wa Waendeshaji Simu (Telephone Operators);<\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\">Maendeleo ya Usimamizi kwa Wasaidizi wa Watendaji Wakuu I;<\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\">Maendeleo ya Usimamizi kwa Wasaidizi wa Watendaji Wakuu II;<\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\">Mtihani wa Umahiri kwa Maafisa Rasilimali Watu;<\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\">Mtihani wa Umahiri kwa Maafisa Kumbukumbu;<\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\">Mtihani wa Umahiri kwa Maafisa Ustawi wa Jamii<\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\">Mtihani wa Umahiri kwa Maafisa Kazi;<\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\">Sheria kwa Maafisa Tawala;<\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\">Sheria kwa Maafisa Watendaji wa Kata\\/Tarafa; na<\\/span><\\/li>\\r\\n\\t<li><span style=\\\"font-size:12pt\\\">Mtihani wa umahiri kwa Maafisa Maendeleo wa vijana;<\\/span><\\/li>\\r\\n<\\/ol>\",\"content_en\":\"<p style=\\\"text-align:justify\\\">Tanzania Public Service College has been administering Public Service Examinations and review programmes since 2003. Circular letter number<br \\/>\\r\\nC\\/CB.49\\/177\\/01A\\/46 dated 13th January 2003 in line with the current Public Service Act No. 8 of 2002 as amended in 2008 mandated the Tanzania PublicService College to run the Public Service Examinations which were formally run by the Public Service Commission (PSC). Public Service Examinations(PSE) and review programmes are primarily provided for public servants who are obliged by their respective schemes of service to undertake to enable them to meet certain criteria for their promotions.<\\/p>\\r\\n\\r\\n<p>Cadres that are covered by public service examinations and review programmes include:<\\/p>\\r\\n\\r\\n<p><br \\/>\\r\\n1. Higher Standard Government Accounting (HSGA)<br \\/>\\r\\n2. Higher Standard Stores Management (HSSM)<br \\/>\\r\\n3. Qualifying Law for Administrative Officers (QLA)<br \\/>\\r\\n4. Qualifying Law for Division Officers (QLD)<br \\/>\\r\\n5. Proficiency Examinations for Labour Officers (PLO)<br \\/>\\r\\n6. Proficiency Examinations for Social Welfare Officers (PSW)<br \\/>\\r\\n7. Proficiency Examinations for Human Resource Officers (PHR)<br \\/>\\r\\n8. Proficiency Examinations for Records Officers (PRO)<br \\/>\\r\\n9. Higher Standard Records Management (HSRM)<br \\/>\\r\\n10. Auditors Qualifying Examinations (AQE)<br \\/>\\r\\n11. Higher Standard Telephone Operators (HSTO)<br \\/>\\r\\n12. Kiswahili Kigumu (KK)<br \\/>\\r\\n13. Management Development for Executive Assistant (MDEA I &amp; II)<br \\/>\\r\\n14. Special Youth Work Examination (SYWE)<\\/p>\",\"slug\":\"public-service-examinations\",\"status\":1,\"created_at\":\"2023-12-19T12:31:22.000000Z\",\"updated_at\":\"2023-12-19T12:39:33.000000Z\"}','2023-12-19 09:40:34','2023-12-19 09:40:34'),(1485,6,'Administration','update','41.222.180.247','http://demo81.eganet.go.tz/tpsc/cms/administration/19','{\"id\":19,\"salutation_en\":\"Dr\",\"salutation_sw\":\"Dkt\",\"fullname\":\"Hamisi Amani\",\"position\":\"0\",\"title_sw\":\"Kaimu Makamu Mkuu wa Chuo Taaluma\",\"title_en\":\"Ag. Deputy Rector-Academic, Research and Consultancy\",\"content_sw\":\"<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\"><span style=\\\"font-size:12.0pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\">Dr. Hamisi Amani is a renowned scholar and visionary leader in the field of education, linguistics and public service currently serving as Ag. Deputy Rector, Academic, research and Consultancy at Tanzania Public Service College (TPSC).<\\/span><\\/span><\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\"><span style=\\\"font-size:12.0pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\">Dr. Amani&#39;s passion for education led him to pursue a degree which led to an award of Bachelor of Arts with Education at the University of Dar es salaam, where he graduated with honor degree in 2007. <\\/span><\\/span><\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\"><span style=\\\"font-size:12.0pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\">Following his Bachelor&#39;s, Dr. Amani obtained a Master&#39;s degree in linguistics from the University of Dar es Salaam in 2010. During his time at the University of Dar es salaam, he immersed himself in various research projects, focusing particularly on contact linguistics and participated in part time basis in the Language of Tanzania Project (LOT) in the development of the Makonde Dictionary. <\\/span><\\/span><\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\"><span style=\\\"font-size:12.0pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\">Driven by a desire to make a tangible contribution in education, Dr. Amani went on to pursue a Ph.D. in Linguistics at the University of Dar es Salaam. His doctoral research focused on analyzing the interplay of social and linguistic factors in structural borrowing from Kiswahili into Chimalaba. His findings highlighted the need for comprehensive strategies that address issues of the influence of Kiswahili on Ethnic Community Languages (ECLs) in Tanzania focusing on the impact of language change. <\\/span><\\/span><\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\"><span style=\\\"font-size:12.0pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\">Upon completing his doctorate, Dr. Amani got a chance to serve in different leadership positions at Tanzania Public Service College (TPSC). He served as the Head of Research, Consultancy and Short Course Department and Head of Public Administration, Leadership and Management Department both at Mtwara Campus. He was then appointed to serve as Campus Director at Singida campus from 2019 to 2023 when he was appointed to the current position of Acting Deputy Rector, Academic, research and Consultancy. In all those leadership roles, Dr. Amani positioned himself as a thought leader in the public service through Tanzania Public Service College and contributed in advising the government and its institutions through his scholarly works of consultancy, research and publications. &nbsp;<\\/span><\\/span><\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\"><span style=\\\"font-size:12.0pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\">In addition to his leadership roles, Dr. Amani has deeply engaged in scholarly works. In consultancy, he has recently engaged in national consultancy works of reviewing and preparation of National Multi-sectoral HIV and AIDS Stigma and Discrimination Reduction Strategy of the Year 2013-2017 for TACAIDS in 2022 and Conducting Stigma Index 2.0 Survey for PLHIV in Tanzania Mainland from 2020 to 2021 for TACAIDS. <\\/span><\\/span><\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\"><span style=\\\"font-size:12.0pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\">In research, Dr. Amani has conducted research on various issues in the public service such as Learning Transfer, Challenges in the Implementation of OPRAS in LGAs, Poverty and Vulnerability Surveys and implementation of staff induction training.&nbsp; He has published extensively in his field of linguistics and in the public service. <\\/span><\\/span><\\/span><\\/span><\\/p>\",\"content_en\":\"<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\"><span style=\\\"font-size:12.0pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\">Dr. Hamisi Amani is a renowned scholar and visionary leader in the field of education, linguistics and public service currently serving as Ag. Deputy Rector, Academic, research and Consultancy at Tanzania Public Service College (TPSC).<\\/span><\\/span><\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\"><span style=\\\"font-size:12.0pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\">Dr. Amani&#39;s passion for education led him to pursue a degree which led to an award of Bachelor of Arts with Education at the University of Dar es salaam, where he graduated with honor degree in 2007. <\\/span><\\/span><\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\"><span style=\\\"font-size:12.0pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\">Following his Bachelor&#39;s, Dr. Amani obtained a Master&#39;s degree in linguistics from the University of Dar es Salaam in 2010. During his time at the University of Dar es salaam, he immersed himself in various research projects, focusing particularly on contact linguistics and participated in part time basis in the Language of Tanzania Project (LOT) in the development of the Makonde Dictionary. <\\/span><\\/span><\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\"><span style=\\\"font-size:12.0pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\">Driven by a desire to make a tangible contribution in education, Dr. Amani went on to pursue a Ph.D. in Linguistics at the University of Dar es Salaam. His doctoral research focused on analyzing the interplay of social and linguistic factors in structural borrowing from Kiswahili into Chimalaba. His findings highlighted the need for comprehensive strategies that address issues of the influence of Kiswahili on Ethnic Community Languages (ECLs) in Tanzania focusing on the impact of language change. <\\/span><\\/span><\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\"><span style=\\\"font-size:12.0pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\">Upon completing his doctorate, Dr. Amani got a chance to serve in different leadership positions at Tanzania Public Service College (TPSC). He served as the Head of Research, Consultancy and Short Course Department and Head of Public Administration, Leadership and Management Department both at Mtwara Campus. He was then appointed to serve as Campus Director at Singida campus from 2019 to 2023 when he was appointed to the current position of Acting Deputy Rector, Academic, research and Consultancy. In all those leadership roles, Dr. Amani positioned himself as a thought leader in the public service through Tanzania Public Service College and contributed in advising the government and its institutions through his scholarly works of consultancy, research and publications. &nbsp;<\\/span><\\/span><\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\"><span style=\\\"font-size:12.0pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\">In addition to his leadership roles, Dr. Amani has deeply engaged in scholarly works. In consultancy, he has recently engaged in national consultancy works of reviewing and preparation of National Multi-sectoral HIV and AIDS Stigma and Discrimination Reduction Strategy of the Year 2013-2017 for TACAIDS in 2022 and Conducting Stigma Index 2.0 Survey for PLHIV in Tanzania Mainland from 2020 to 2021 for TACAIDS. <\\/span><\\/span><\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\"><span style=\\\"font-size:12.0pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\">In research, Dr. Amani has conducted research on various issues in the public service such as Learning Transfer, Challenges in the Implementation of OPRAS in LGAs, Poverty and Vulnerability Surveys and implementation of staff induction training.&nbsp; He has published extensively in his field of linguistics and in the public service. <\\/span><\\/span><\\/span><\\/span><\\/p>\",\"photo_url\":\"e632e3684ff354e9d0ad1fc95c6a4fd9.jpeg\",\"email\":\"info@tpsc.go.tz\",\"phone\":\"+255 22 2152982\",\"created_at\":\"2023-12-14T12:07:07.000000Z\",\"updated_at\":\"2023-12-19T10:22:56.000000Z\",\"slug\":\"ag-deputy-rector-academic-research-and-consultancy\"}','2024-01-02 05:26:50','2024-01-02 05:26:50'),(1486,6,'Administration','update','41.222.180.247','http://demo81.eganet.go.tz/tpsc/cms/administration/11','{\"id\":11,\"salutation_en\":\"Dr\",\"salutation_sw\":\"Dkt.\",\"fullname\":\"Ernest Francis Mabonesho\",\"position\":\"1\",\"title_sw\":\"Mkuu wa Chuo na Mtendaji Mkuu\",\"title_en\":\"Rector and Chief Executive Officer\",\"content_sw\":\"<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\"><span style=\\\"font-size:12.0pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\"><span style=\\\"color:black\\\">Dr. Ernest Francis Mabonesho is a Senior Lecturer<\\/span><\\/span><\\/span> <span style=\\\"font-size:12.0pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\"><span style=\\\"color:black\\\">and acting Rector and Chief Executive Officer at the <a name=\\\"_Hlk153736787\\\">Tanzania Public Service College <\\/a>(TPSC).&nbsp; He is a highly accomplished professional in the fields of accounts, finance, and education. He holds a PhD in Accounting and Finance and an MSc. International Accounting and Finance from the University of Strathclyde, United Kingdom (UK). He also holds a Bachelor of Arts in Education from the University of Dar es Salaam and a Diploma in Education from the Dar es Salaam Teachers College <\\/span><\\/span><\\/span><\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\"><span style=\\\"font-size:12.0pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\"><span style=\\\"color:black\\\">In his current role as the acting Rector and Chief Executive Officer at TPSC, Dr. Mabonesho is responsible for overseeing the implementation of policies and initiatives aimed at enhancing the efficiency, transparency, and accountability of the public service sector. He is dedicated to promoting professional development, fostering a culture of integrity, and optimizing resource management within the public service.<\\/span><\\/span><\\/span><\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\"><span style=\\\"font-size:12.0pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\"><span style=\\\"color:black\\\">He joined Tanzania Public Service College in September 2021 as Deputy Rector of Planning, Finance, and Administration and assumed the role of Acting Rector and Chief Executive Officer in February 2023.&nbsp; <\\/span><\\/span><\\/span><\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\"><span style=\\\"font-size:12.0pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\"><span style=\\\"color:black\\\">Before joining TPSC, Dr. Ernest was the Dean of the Faculty of Accounting, Banking, and Finance at the Institute of Financial Management (IFM). In this role, he exhibited exceptional leadership skills and a deep commitment to academic excellence in shaping the institute&#39;s curriculum, ensuring that students receive a comprehensive education in financial management and accounting.<\\/span><\\/span><\\/span><\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\"><span style=\\\"font-size:12.0pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\"><span style=\\\"color:black\\\">Dr. Ernest Francis Mabonesho&#39;s remarkable academic background, combined with his experience and leadership skills, has made significant contributions to the development and advancement of the Tanzania Public College.<\\/span><\\/span><\\/span><\\/span><\\/span><\\/p>\",\"content_en\":\"<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\"><span style=\\\"font-size:12.0pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\"><span style=\\\"color:black\\\">Dr. Ernest Francis Mabonesho is a Senior Lecturer<\\/span><\\/span><\\/span> <span style=\\\"font-size:12.0pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\"><span style=\\\"color:black\\\">and acting Rector and Chief Executive Officer at the <a name=\\\"_Hlk153736787\\\">Tanzania Public Service College <\\/a>(TPSC).&nbsp; He is a highly accomplished professional in the fields of accounts, finance, and education. He holds a PhD in Accounting and Finance and an MSc. International Accounting and Finance from the University of Strathclyde, United Kingdom (UK). He also holds a Bachelor of Arts in Education from the University of Dar es Salaam and a Diploma in Education from the Dar es Salaam Teachers College <\\/span><\\/span><\\/span><\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\"><span style=\\\"font-size:12.0pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\"><span style=\\\"color:black\\\">In his current role as the acting Rector and Chief Executive Officer at TPSC, Dr. Mabonesho is responsible for overseeing the implementation of policies and initiatives aimed at enhancing the efficiency, transparency, and accountability of the public service sector. He is dedicated to promoting professional development, fostering a culture of integrity, and optimizing resource management within the public service.<\\/span><\\/span><\\/span><\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\"><span style=\\\"font-size:12.0pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\"><span style=\\\"color:black\\\">He joined Tanzania Public Service College in September 2021 as Deputy Rector of Planning, Finance, and Administration and assumed the role of Acting Rector and Chief Executive Officer in February 2023.&nbsp; <\\/span><\\/span><\\/span><\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\"><span style=\\\"font-size:12.0pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\"><span style=\\\"color:black\\\">Before joining TPSC, Dr. Ernest was the Dean of the Faculty of Accounting, Banking, and Finance at the Institute of Financial Management (IFM). In this role, he exhibited exceptional leadership skills and a deep commitment to academic excellence in shaping the institute&#39;s curriculum, ensuring that students receive a comprehensive education in financial management and accounting.<\\/span><\\/span><\\/span><\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:11pt\\\"><span style=\\\"font-family:Calibri,sans-serif\\\"><span style=\\\"font-size:12.0pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\"><span style=\\\"color:black\\\">Dr. Ernest Francis Mabonesho&#39;s remarkable academic background, combined with his experience and leadership skills, has made significant contributions to the development and advancement of the Tanzania Public College.<\\/span><\\/span><\\/span><\\/span><\\/span><\\/p>\",\"photo_url\":\"965a4bcdd92b970e2197be0ebb97381a.jpeg\",\"email\":\"info@tpsc.go.tz\",\"phone\":\"+255 22 2152982\",\"created_at\":\"2023-12-14T10:32:11.000000Z\",\"updated_at\":\"2023-12-19T09:02:09.000000Z\",\"slug\":\"rector-and-chief-executive-officer\"}','2024-01-02 05:40:01','2024-01-02 05:40:01'),(1487,6,'WelcomeNote','update','41.222.180.247','http://demo81.eganet.go.tz/tpsc/cms/welcome/2','{\"id\":2,\"summary_en\":null,\"summary_sw\":null,\"content_sw\":\"<p style=\\\"text-align:justify\\\">Chuo cha Utumishi wa Umma Tanzania (TPSC) kilianzishwa mwaka 2000 kwa sheria ya Wakala za Serikali Na. 30 ya mwaka 1997. Lengo la kuanzishwa kwake lilikuwa kuziba pengo la kuwa na taasisi ya mafunzo jumuishi kwa utumishi wa umma kukidhi mahitaji yanayobadilika ya utumishi wa umma yaliyosababishwa na maboresho ya utumishi wa umma na haja ya kuwa na chuo cha utumishi wa umma kinachojitegemea chenye uwezo wa fedha endelevu.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">Kutokana na hali hiyo, TPSC ni mtoa huduma ya maarifa na stadi anayependelewa kwa utumishi wa umma katika maeneo ya uongozi, Usimamizi wa Kimkakati, Utawala, maadili na uwajibika. Pia ni taasisi ya kujenga utamaduni wa elimu endelevu kwa watumishi wa umma. Wateja wa TPSC ni pamoja na Serikali Kuu na Serikali za Mitaa, idara zinzojitegemea, Wakala za Serikali, wanaohitimu elimu ya Sekondari, umma kwa jumla na sekta binafsi.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">TPSC ina Kampasi sita zilizojengwa kimkakati jijini Dar es Salaam, Tabora, Mtwara, Singida, Tanga na Mbeya ili iwe karibu na wateja wake nchi nzima.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">Taasisi inatoa masomo katika viwango vitatu vya Cheti (Basic Technician Certificate), Diploma na Shahada ya Kwanza (BA) myanayofaa kwa sekta ya umma na binafsi katika Kampasi zake.Licha ya Programu hizo, TPSCinatoa masomo ya mapitio kwa ajili ya Mitihani ya Utumishi wa Umma na Huduma za Ushauri.Hivi karibuni imeanza ktumika mtindo wa Elimu na Mafunzo yanayotokana na Weledi. (CBET) kama njia ya maendeleo, namna ya kupata Elimu bora na Mafunzo yanayokidhi mahitaji ya soko la ajira la kudumu na linalo haraka sana.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">Chuo cha utumishi wa umma Tanzania kimesanifu upya tovuti yakekwa manufaa ya wateja, wadau na umma kwa jumla. Tovuti hii ni chombo cha kupasha habari kinachokusudiakuuarifu umma kwa jumlakuhusu Chuo cha Utumishi umma, huduma inazozitoa, muundo wake na shughuli za chuo kwa jumla.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">Inatarajiwa kwamba, tovuti hii iliyoboreshwa itakuwa chanzo cha taarifa kinachofaa kwa wateja wetu, wadau na umma kwa jumla.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">Tunawakaribisha wote mtembelee tovuti yetu.<a href=\\\"http:\\/\\/www.tpsc.go.tz\\/\\\"><u>www.tpsc.go.tz<\\/u><\\/a><\\/p>\",\"content_en\":\"<p style=\\\"text-align:justify\\\">The Tanzania Public Service College (TPSC) is a Technical Institutions in Tanzania was established in 2000 under the ambit of the Executive Agencies Act No 30 of 1997. The aim of it&rsquo;s establishment was to fill an extant void in terms of a comprehensive training facility for Public Service, to meet the changing needs of the Public Services resulted from the Public Service Reforms, and the need for an autonomous financially sustainable public service College.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">It is in light of the above that the TPSC is the preferred service provider of knowledge and skills to the public service, but also as a part of building a culture of continuous learning for public servants. The customers of TPSC include; central and local government, independent departments, executive agencies; secondary school leavers, the general public and private sector.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">TPSC has&nbsp;<strong>Six Campuses&nbsp;<\\/strong>strategically located in&nbsp;<strong>Dar es Salaam<\\/strong><strong>, Tabora, Mtwara, Singida, Tanga and Mbeya&nbsp;<\\/strong>to be close to its customers countrywide<strong>.<\\/strong><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">The Institute is offering Basic Technician Certificate, Diploma, and Bachelor Degree Programmes suitable for public and private sectors in its campuses. Besides these programmes, TPSC is offering review classes for Public Service Examinations and consultancy services. It has recently adopted the Competence-Based Education and Training (CBET) approach as the way forward, the way to attain the quality of education and training that meets the demands of a dynamic and permanently changing labour market.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">TPSC has redesigned its website to take in to consideration the various improvements taking place in its core activities. We believe this Website will be an informative tool to inform and educated the general public about the Tanzania Public Service College, the products and services offered organization structure and the overall operation of the College.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">It is our expectations that, this improved website will be useful to our customers, stakeholders, general public and the rest.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">We welcome you all to visit our website at:&nbsp;<a href=\\\"http:\\/\\/www.tpsc.go.tz\\/\\\"><u>www.tpsc.go.tz<\\/u><\\/a>.<\\/p>\",\"status\":\"1\",\"created_at\":\"2023-12-14T13:34:08.000000Z\",\"updated_at\":\"2023-12-14T10:34:08.000000Z\"}','2024-01-02 05:58:13','2024-01-02 05:58:13'),(1488,6,'Administration','update','41.222.180.247','http://demo81.eganet.go.tz/tpsc/cms/administration/12','{\"id\":12,\"salutation_en\":\"Mr\",\"salutation_sw\":\"Bw.\",\"fullname\":\"Shakiru Abdulkarim\",\"position\":\"0\",\"title_sw\":\"Mkuu wa Kitengo cha Mawasiliano na Masoko\",\"title_en\":\"Head of Communication and Marketing\",\"content_sw\":\"<p style=\\\"text-align:justify\\\">Shakiru Abdulkarim ni mtaalamu mwenye uzoefu wa miaka kumi na tisa katika nyanja za mawasiliano ya umma, masoko na usimamizi wa mradi. Kwa sasa anahudumu kama Mkuu wa Kitengo Mawasiliano na Masoko anayehusika na kupanga, kuendeleza na kutekeleza mikakati ya mawasiliano na masoko na kusimamia shughuli za mahusiano ya umma ya Chuo.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">Kabla ya kujiunga na Chuo, Shakiru amewahi kufanya kazi na Wakala wa Mafunzo kwa Njia ya Mtandao (TaGLA) kama Afisa Mkuu wa Masoko, Taasisi ya Miradi na Maendeleo ya Miundombinu ya UTT ( UTT-PID) kama Msimamizi Mkuu wa Miradi, na Dhamana ya Uwekezaji Tanzania ( UTT) &nbsp;kama Afisa Mwendaji Mkuu na Kampuni ya Mawasiliano Tanzania (TTCL )kama Afisa Huduma kwa Wateja.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">Akiwa na uzoefu mkubwa katika mawasiliano ya umma, Masoko, usimamizi wa miradi, na uendeshaji, Shakiru anaendelea kutoa mchango muhimu katika kuleta mafanikio kwa chou.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">Shakiru ana Shahada ya Kwanza ya Sanaa na Shahada ya Uzamili ya Usimamizi &nbsp;wa Biashara katika Masoko kutoka Chuo Kikuu cha Dar es Salaam na Chuo Kikuu Huria cha Tanzania mtawalia.<\\/p>\",\"content_en\":\"<p style=\\\"text-align:justify\\\">Shakiru Abdulkarim is a dynamic professional with nineteen years of extensive experience in the fields of corporate communication, marketing, and project management. Currently serving as the Head of Communication and Marketing responsible for planning, development, and implementation of college marketing strategies, communications, and public relations activities.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">Shakiru has previously worked with Tanzania Global Learning Agency as Principal Marketing Officer, UTT Projects and Infrastructure Development PLC as Head of Project Management, Unit Trust of Tanzania as Principal Operations Offer, and Tanzania Telecommunication Company Ltd as Customer Service officer.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">With his strong background in communication, marketing, project management, and operations, Shakiru continues to make valuable contributions in driving success for the college and achieving remarkable results.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">He holds a Bachelor of Arts with horns and a Master of Business Administration in Marketing from the University of Dar es Salaam and Open University of Tanzania respectively.<\\/p>\",\"photo_url\":\"94e56ab29dd3a01be6ba6a0b4c7ffbdb.jpeg\",\"email\":\"abdulkarim.shakiru@tpsc.go.tz\",\"phone\":\"+2556542428\",\"created_at\":\"2023-12-14T11:31:59.000000Z\",\"updated_at\":\"2023-12-19T11:51:54.000000Z\",\"slug\":\"head-of-communication-and-marketinging\"}','2024-01-02 11:23:15','2024-01-02 11:23:15'),(1489,6,'AdministrationCategoriesMembers','update','41.59.251.78','http://demo81.eganet.go.tz/tpsc/cms/administration_categories_members/27','{\"id\":27,\"category_id\":\"5\",\"member_id\":\"30\",\"title_en\":\"Ag. Finance and Accounts Manager\",\"title_sw\":\"Kaimu Meneja  Fedha na Uhasibu\",\"parent\":0,\"position\":\"4\",\"created_at\":\"2023-12-19T08:49:42.000000Z\",\"updated_at\":\"2023-12-19T08:49:42.000000Z\"}','2024-01-04 04:18:00','2024-01-04 04:18:00'),(1490,6,'AdministrationCategoriesMembers','update','41.59.251.78','http://demo81.eganet.go.tz/tpsc/cms/administration_categories_members/13','{\"id\":13,\"category_id\":\"5\",\"member_id\":\"19\",\"title_en\":\"Ag.Deputy Rector - Academic, Research and Consultancy\",\"title_sw\":\"Kaimu Makamu Mkuu wa Chuo -Taaluma, Tafiti na Shauri za Kitaalam\",\"parent\":0,\"position\":\"2\",\"created_at\":\"2023-12-14T12:39:36.000000Z\",\"updated_at\":\"2023-12-14T12:39:36.000000Z\"}','2024-01-04 04:19:27','2024-01-04 04:19:27'),(1491,6,'Administration','update','41.59.251.78','http://demo81.eganet.go.tz/tpsc/cms/administration/16','{\"id\":16,\"salutation_en\":\"Mr.\",\"salutation_sw\":\"Ndg.\",\"fullname\":\"Sijali Korojelo\",\"position\":\"0\",\"title_sw\":\"Mkurugenzi\",\"title_en\":\"Director\",\"content_sw\":\"<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:12pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\"><span style=\\\"font-family:&quot;Cambria&quot;,serif\\\"><span style=\\\"color:#0e101a\\\">Sijali Petro Korojelo is an acting Director of Public Service in Service Training. In the past, he served as the manager of programme at TPSC Mtwara campus (2016), a campus director of the Singida and Tanga campuses (2017-2019), and the director of Global Learning Centre (2020-2022).<\\/span><\\/span><\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:12pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\"><span style=\\\"font-family:&quot;Cambria&quot;,serif\\\"><span style=\\\"color:#0e101a\\\">He holds a Bachelor&#39;s and a Master&rsquo;s degree in Computer Science from the University of Dar es Salaam, he has also attended several professional training in the area of ICT and computer science.&nbsp;<\\/span><\\/span><\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:12pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\"><span style=\\\"font-family:&quot;Cambria&quot;,serif\\\"><span style=\\\"color:#0e101a\\\">Korojelo has published several articles in the area of Computing and ICT. Some of his publications include <\\/span><\\/span><span style=\\\"color:blue\\\"><u><span style=\\\"font-family:&quot;Cambria&quot;,serif\\\"><span style=\\\"color:#4a6ee0\\\">Enhanced Authentication on Targeted Online Surveys: A Case of Online Course Evaluation System<\\/span><\\/span><\\/u><\\/span><span style=\\\"font-family:&quot;Cambria&quot;,serif\\\"><span style=\\\"color:#0e101a\\\"> (at the International Journal on New Computer Architectures and Their Applications) and&nbsp;<\\/span><\\/span><span style=\\\"color:blue\\\"><u><span style=\\\"font-family:&quot;Cambria&quot;,serif\\\"><span style=\\\"color:#4a6ee0\\\"><a href=\\\"https:\\/\\/scholar.google.com\\/citations?view_op=view_citation&amp;hl=en&amp;user=c0X5M5AAAAAJ&amp;citation_for_view=c0X5M5AAAAAJ:u5HHmVD_uO8C\\\" style=\\\"color:blue; text-decoration:underline\\\" target=\\\"_blank\\\"><span style=\\\"color:#4a6ee0\\\">Online Surveys System with Enhanced Authentication Intelligence: A Case of online course evaluation system<\\/span><\\/a><\\/span><\\/span><\\/u><\\/span><span style=\\\"font-family:&quot;Cambria&quot;,serif\\\"><span style=\\\"color:#0e101a\\\">&nbsp;(at Springer).<\\/span><\\/span><\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">&nbsp;<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:12pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\"><span style=\\\"font-family:&quot;Cambria&quot;,serif\\\"><span style=\\\"color:#0e101a\\\">His areas of interest include information systems, databases, computer networking, and cloud computing.<\\/span><\\/span><\\/span><\\/span><\\/p>\",\"content_en\":\"<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:12pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\"><span style=\\\"font-family:&quot;Cambria&quot;,serif\\\"><span style=\\\"color:#0e101a\\\">Sijali Petro Korojelo is an acting Director of Public Service in Service Training. In the past, he served as the manager of programme at TPSC Mtwara campus (2016), a campus director of the Singida and Tanga campuses (2017-2019), and the director of Global Learning Centre (2020-2022).<\\/span><\\/span><\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:12pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\"><span style=\\\"font-family:&quot;Cambria&quot;,serif\\\"><span style=\\\"color:#0e101a\\\">He holds a Bachelor&#39;s and a Master&rsquo;s degree in Computer Science from the University of Dar es Salaam, he has also attended several professional training in the area of ICT and computer science.&nbsp;<\\/span><\\/span><\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:12pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\"><span style=\\\"font-family:&quot;Cambria&quot;,serif\\\"><span style=\\\"color:#0e101a\\\">Korojelo has published several articles in the area of Computing and ICT. Some of his publications include <\\/span><\\/span><span style=\\\"color:blue\\\"><u><span style=\\\"font-family:&quot;Cambria&quot;,serif\\\"><span style=\\\"color:#4a6ee0\\\">Enhanced Authentication on Targeted Online Surveys: A Case of Online Course Evaluation System<\\/span><\\/span><\\/u><\\/span><span style=\\\"font-family:&quot;Cambria&quot;,serif\\\"><span style=\\\"color:#0e101a\\\"> (at the International Journal on New Computer Architectures and Their Applications) and&nbsp;<\\/span><\\/span><span style=\\\"color:blue\\\"><u><span style=\\\"font-family:&quot;Cambria&quot;,serif\\\"><span style=\\\"color:#4a6ee0\\\"><a href=\\\"https:\\/\\/scholar.google.com\\/citations?view_op=view_citation&amp;hl=en&amp;user=c0X5M5AAAAAJ&amp;citation_for_view=c0X5M5AAAAAJ:u5HHmVD_uO8C\\\" style=\\\"color:blue; text-decoration:underline\\\" target=\\\"_blank\\\"><span style=\\\"color:#4a6ee0\\\">Online Surveys System with Enhanced Authentication Intelligence: A Case of online course evaluation system<\\/span><\\/a><\\/span><\\/span><\\/u><\\/span><span style=\\\"font-family:&quot;Cambria&quot;,serif\\\"><span style=\\\"color:#0e101a\\\">&nbsp;(at Springer).<\\/span><\\/span><\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:12pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\"><span style=\\\"font-family:&quot;Cambria&quot;,serif\\\"><span style=\\\"color:#0e101a\\\">His areas of interest include information systems, databases, computer networking, and cloud computing.<\\/span><\\/span><\\/span><\\/span><\\/p>\",\"photo_url\":\"4cb1079629c181bd699f9ba18e9a057a.jpeg\",\"email\":\"sijali.korojelo@tpsc.go.tz\",\"phone\":\"0766000000\",\"created_at\":\"2023-12-14T11:52:23.000000Z\",\"updated_at\":\"2023-12-19T11:03:12.000000Z\",\"slug\":\"director-2\"}','2024-01-04 04:23:28','2024-01-04 04:23:28'),(1492,6,'Administration','update','41.59.251.78','http://demo81.eganet.go.tz/tpsc/cms/administration/16','{\"id\":16,\"salutation_en\":\"Mr.\",\"salutation_sw\":\"Ndg.\",\"fullname\":\"Sijali Korojelo\",\"position\":\"0\",\"title_sw\":\"Mkurugenzi\",\"title_en\":\"Director\",\"content_sw\":\"<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:12pt\\\"><span style=\\\"color:#0e101a\\\">Sijali Petro Korojelo is an acting Director of Public Service in Service Training. In the past, he served as the manager of programme at TPSC Mtwara campus (2016), a campus director of the Singida and Tanga campuses (2017-2019), and the director of Global Learning Centre (2020-2022).<\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:12pt\\\"><span style=\\\"color:#0e101a\\\">He holds a Bachelor&#39;s and a Master&rsquo;s degree in Computer Science from the University of Dar es Salaam, he has also attended several professional training in the area of ICT and computer science.&nbsp;<\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:12pt\\\"><span style=\\\"color:#0e101a\\\">Korojelo has published several articles in the area of Computing and ICT. Some of his publications include <\\/span><span style=\\\"color:blue\\\"><u><span style=\\\"color:#4a6ee0\\\">Enhanced Authentication on Targeted Online Surveys: A Case of Online Course Evaluation System<\\/span><\\/u><\\/span><span style=\\\"color:#0e101a\\\"> (at the International Journal on New Computer Architectures and Their Applications) and&nbsp;<\\/span><span style=\\\"color:blue\\\"><u><span style=\\\"color:#4a6ee0\\\"><a href=\\\"https:\\/\\/scholar.google.com\\/citations?view_op=view_citation&amp;hl=en&amp;user=c0X5M5AAAAAJ&amp;citation_for_view=c0X5M5AAAAAJ:u5HHmVD_uO8C\\\" style=\\\"color:blue; text-decoration:underline\\\" target=\\\"_blank\\\"><span style=\\\"color:#4a6ee0\\\">Online Surveys System with Enhanced Authentication Intelligence: A Case of online course evaluation system<\\/span><\\/a><\\/span><\\/u><\\/span><span style=\\\"color:#0e101a\\\">&nbsp;(at Springer).<\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">&nbsp;<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:12pt\\\"><span style=\\\"color:#0e101a\\\">His areas of interest include information systems, databases, computer networking, and cloud computing.<\\/span><\\/span><\\/p>\",\"content_en\":\"<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:12pt\\\"><span style=\\\"color:#0e101a\\\">Sijali Petro Korojelo is an acting Director of Public Service in Service Training. In the past, he served as the manager of programme at TPSC Mtwara campus (2016), a campus director of the Singida and Tanga campuses (2017-2019), and the director of Global Learning Centre (2020-2022).<\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:12pt\\\"><span style=\\\"color:#0e101a\\\">He holds a Bachelor&#39;s and a Master&rsquo;s degree in Computer Science from the University of Dar es Salaam, he has also attended several professional training in the area of ICT and computer science.&nbsp;<\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:12pt\\\"><span style=\\\"color:#0e101a\\\">Korojelo has published several articles in the area of Computing and ICT. Some of his publications include <\\/span><span style=\\\"color:blue\\\"><u><span style=\\\"color:#4a6ee0\\\">Enhanced Authentication on Targeted Online Surveys: A Case of Online Course Evaluation System<\\/span><\\/u><\\/span><span style=\\\"color:#0e101a\\\"> (at the International Journal on New Computer Architectures and Their Applications) and&nbsp;<\\/span><span style=\\\"color:blue\\\"><u><span style=\\\"color:#4a6ee0\\\"><a href=\\\"https:\\/\\/scholar.google.com\\/citations?view_op=view_citation&amp;hl=en&amp;user=c0X5M5AAAAAJ&amp;citation_for_view=c0X5M5AAAAAJ:u5HHmVD_uO8C\\\" style=\\\"color:blue; text-decoration:underline\\\" target=\\\"_blank\\\"><span style=\\\"color:#4a6ee0\\\">Online Surveys System with Enhanced Authentication Intelligence: A Case of online course evaluation system<\\/span><\\/a><\\/span><\\/u><\\/span><span style=\\\"color:#0e101a\\\">&nbsp;(at Springer).<\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:12pt\\\"><span style=\\\"color:#0e101a\\\">His areas of interest include information systems, databases, computer networking, and cloud computing.<\\/span><\\/span><\\/p>\",\"photo_url\":\"4cb1079629c181bd699f9ba18e9a057a.jpeg\",\"email\":\"sijali.korojelo@tpsc.go.tz\",\"phone\":\"+255 22 2152982\",\"created_at\":\"2023-12-14T11:52:23.000000Z\",\"updated_at\":\"2024-01-04T07:23:28.000000Z\",\"slug\":\"director-2\"}','2024-01-04 04:25:44','2024-01-04 04:25:44'),(1493,6,'Administration','update','41.59.251.78','http://demo81.eganet.go.tz/tpsc/cms/administration/16','{\"id\":16,\"salutation_en\":\"Mr.\",\"salutation_sw\":\"Ndg.\",\"fullname\":\"Sijali Korojelo\",\"position\":\"0\",\"title_sw\":\"Mkurugenzi\",\"title_en\":\"Director\",\"content_sw\":\"<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:12pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\"><span style=\\\"color:#252525\\\">Sijali Petro Korojelo ni Kaimu Mkurugenzi wa Mafunzo kwa Watumishi wa Umma wa Chuo cha Utumishi wa Umma Tanzania tangu Februari 2023. Kabla ya hapo, amewahi kufanya kazi kama Meneja Mafunzo wa Kampasi ya Mtwara (2016), Mkurugenzi wa Kampasi za Tanga na Singida (2017-2019) na Kaimu Mkurugenzi wa Kituo cha Mafunzo kwa Njia ya Mtandao cha Chuo cha Utumishi wa Umma Tanzania (2020-2022). Korojelo pia amewahi kuhudumu kama mtafiti katika idara ya Tehama ya Chuo Kikuu cha Amsterdam, Uholanzi (2011-2012).<\\/span><\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:12pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\"><span style=\\\"color:#252525\\\">Korojelo ana shahada ya kwanza na shahada ya uzamili katika Sayansi ya Kompyuta toka Chuo Kikuu cha Dar es Salaam. Amewahi pia kuhudhuria mafunzo kadhaa ya kujenga umahiri katika maeneo ya uongozi, utawala na TEHAMA. Maeneo yake pendwa ya tafiti ni pamoja na uongozi, utawala, mifumo ya Tehama, kanzudata za TEHAMA pamoja na mitandao ya kompyuta.<\\/span><\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:12pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\"><span style=\\\"color:#252525\\\">Katika vipindi vyake mbalimbali vya kuhudumu, Korojelo ametoa machapisho kadhaa katika maeneo ya TEHAMA na menejimenti.<\\/span><\\/span><\\/span><\\/p>\",\"content_en\":\"<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:12pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\"><span style=\\\"color:#252525\\\">Sijali Petro Korojelo has been the acting Director of Public Service in Service Training since February 2023. In the past, he served as the manager of programme at the TPSC Mtwara campus (2016), a campus director for the Singida and Tanga campuses (2017 - 2019), and an acting director of the Global Learning Centre (2020 - 2022). Furthermore, he once served as a researcher at the Informatics Institute of the University of Amsterdam, Netherlands (2011 - 2012).<\\/span><\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:12pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\"><span style=\\\"color:#252525\\\">Korojelo holds a bachelor&#39;s and a master&rsquo;s degree in Computer Science from the University of Dar es Salaam. He has also attended several professional training programme in the areas of computing and ICT. His areas of interest include management, administration, information systems, databases, computer networking, and cloud computing.<\\/span><\\/span><\\/span><\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><span style=\\\"font-size:12pt\\\"><span style=\\\"font-family:&quot;Times New Roman&quot;,serif\\\"><span style=\\\"color:#252525\\\">During the course of his actions, Korojelo has published several articles in the areas of management, computing, and ICT. Some of his publications include <span style=\\\"color:blue\\\"><u><span style=\\\"color:#252525\\\">Enhanced Authentication on Targeted Online Surveys: A Case of Online Course Evaluation System<\\/span><\\/u><\\/span> (at the International Journal on New Computer Architectures and Their Applications), <span style=\\\"color:blue\\\"><u><span style=\\\"color:#252525\\\">Online<a href=\\\"https:\\/\\/scholar.google.com\\/citations?view_op=view_citation&amp;hl=en&amp;user=c0X5M5AAAAAJ&amp;citation_for_view=c0X5M5AAAAAJ:u5HHmVD_uO8C\\\" style=\\\"color:blue; text-decoration:underline\\\"><span style=\\\"color:#252525\\\">&nbsp;Surveys System with Enhanced Authentication Intelligence: A Case of Online Course Evaluation System<\\/span><\\/a><\\/span><\\/u><\\/span> (at Springer), and <span style=\\\"color:blue\\\"><u><span style=\\\"color:#252525\\\">Uplifting Motivation of Tanzanian Public Service Personnel for Improved Service Delivery: The Reflection of Public Service Motivation Theory<\\/span><\\/u><\\/span> (at the International Journal of African and Asian.<\\/span><\\/span><\\/span><\\/p>\",\"photo_url\":\"4cb1079629c181bd699f9ba18e9a057a.jpeg\",\"email\":\"sijali.korojelo@tpsc.go.tz\",\"phone\":\"+255 22 2152982\",\"created_at\":\"2023-12-14T11:52:23.000000Z\",\"updated_at\":\"2024-01-04T07:25:44.000000Z\",\"slug\":\"director-2\"}','2024-01-05 10:40:22','2024-01-05 10:40:22'),(1494,6,'Administration','update','154.74.127.154','http://demo81.eganet.go.tz/tpsc/cms/administration/11','{\"id\":11,\"salutation_en\":\"Dr\",\"salutation_sw\":\"Dkt.\",\"fullname\":\"Ernest Francis Mabonesho\",\"position\":\"1\",\"title_sw\":\"Mkuu wa Chuo na Mtendaji Mkuu\",\"title_en\":\"Rector and Chief Executive Officer\",\"content_sw\":\"<p style=\\\"text-align: justify;\\\">Dr. Ernest Francis Mabonesho is a Senior Lecturer and acting Rector and Chief Executive Officer at the Tanzania Public Service College (TPSC).&nbsp;&nbsp;He is a highly accomplished professional in the fields of accounts, finance, and education. He holds a PhD in Accounting and Finance and an MSc. International Accounting and Finance from the University of Strathclyde, United Kingdom (UK). He also holds a Bachelor of Arts in Education from the University of Dar es Salaam and a Diploma in Education from the Dar es Salaam Teachers College<\\/p>\\r\\n\\r\\n<p style=\\\"text-align: justify;\\\">In his current role as the acting Rector and Chief Executive Officer at TPSC, Dr. Mabonesho is responsible for overseeing the implementation of policies and initiatives aimed at enhancing the efficiency, transparency, and accountability of the public service sector. He is dedicated to promoting professional development, fostering a culture of integrity, and optimizing resource management within the public service.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align: justify;\\\">He joined Tanzania Public Service College in September 2021 as Deputy Rector of Planning, Finance, and Administration and assumed the role of Acting Rector and Chief Executive Officer in February 2023.&nbsp;<\\/p>\\r\\n\\r\\n<p style=\\\"text-align: justify;\\\">Before joining TPSC, Dr. Ernest was the Dean of the Faculty of Accounting, Banking, and Finance at the Institute of Financial Management (IFM). In this role, he exhibited exceptional leadership skills and a deep commitment to academic excellence in shaping the institute&#39;s curriculum, ensuring that students receive a comprehensive education in financial management and accounting.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align: justify;\\\">Dr. Ernest Francis Mabonesho&#39;s remarkable academic background, combined with his experience and leadership skills, has made significant contributions to the development and advancement of the Tanzania Public College.<\\/p>\",\"content_en\":\"<p style=\\\"text-align:justify\\\">Dr. Ernest Francis Mabonesho is a Senior Lecturer and acting Rector and Chief Executive Officer at the Tanzania Public Service College (TPSC).&nbsp;&nbsp;He is a highly accomplished professional in the fields of accounts, finance, and education. He holds a PhD in Accounting and Finance and an MSc. International Accounting and Finance from the University of Strathclyde, United Kingdom (UK). He also holds a Bachelor of Arts in Education from the University of Dar es Salaam and a Diploma in Education from the Dar es Salaam Teachers College<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">In his current role as the acting Rector and Chief Executive Officer at TPSC, Dr. Mabonesho is responsible for overseeing the implementation of policies and initiatives aimed at enhancing the efficiency, transparency, and accountability of the public service sector. He is dedicated to promoting professional development, fostering a culture of integrity, and optimizing resource management within the public service.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">He joined Tanzania Public Service College in September 2021 as Deputy Rector of Planning, Finance, and Administration and assumed the role of Acting Rector and Chief Executive Officer in February 2023.&nbsp;<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">Before joining TPSC, Dr. Ernest was the Dean of the Faculty of Accounting, Banking, and Finance at the Institute of Financial Management (IFM). In this role, he exhibited exceptional leadership skills and a deep commitment to academic excellence in shaping the institute&#39;s curriculum, ensuring that students receive a comprehensive education in financial management and accounting.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\">Dr. Ernest Francis Mabonesho&#39;s remarkable academic background, combined with his experience and leadership skills, has made significant contributions to the development and advancement of the Tanzania Public College.<\\/p>\",\"photo_url\":\"965a4bcdd92b970e2197be0ebb97381a.jpeg\",\"email\":\"info@tpsc.go.tz\",\"phone\":\"+255 22 2152982\",\"created_at\":\"2023-12-14T10:32:11.000000Z\",\"updated_at\":\"2024-01-02T08:40:01.000000Z\",\"slug\":\"rector-and-chief-executive-officer\"}','2024-01-09 05:31:35','2024-01-09 05:31:35'),(1495,6,'Administration','update','154.74.127.154','http://demo81.eganet.go.tz/tpsc/cms/administration/16','{\"id\":16,\"salutation_en\":\"Mr.\",\"salutation_sw\":\"Ndg.\",\"fullname\":\"Sijali Korojelo\",\"position\":\"0\",\"title_sw\":\"Mkurugenzi\",\"title_en\":\"Director\",\"content_sw\":\"<p style=\\\"text-align: justify;\\\">Sijali Petro Korojelo ni Kaimu Mkurugenzi wa Mafunzo kwa Watumishi wa Umma wa Chuo cha Utumishi wa Umma Tanzania tangu Februari 2023. Kabla ya hapo, amewahi kufanya kazi kama Meneja Mafunzo wa Kampasi ya Mtwara (2016), Mkurugenzi wa Kampasi za Tanga na Singida (2017-2019) na Kaimu Mkurugenzi wa Kituo cha Mafunzo kwa Njia ya Mtandao cha Chuo cha Utumishi wa Umma Tanzania (2020-2022). Korojelo pia amewahi kuhudumu kama mtafiti katika idara ya Tehama ya Chuo Kikuu cha Amsterdam, Uholanzi (2011-2012).<\\/p>\\r\\n\\r\\n<p style=\\\"text-align: justify;\\\">Korojelo ana shahada ya kwanza na shahada ya uzamili katika Sayansi ya Kompyuta toka Chuo Kikuu cha Dar es Salaam. Amewahi pia kuhudhuria mafunzo kadhaa ya kujenga umahiri katika maeneo ya uongozi, utawala na TEHAMA. Maeneo yake pendwa ya tafiti ni pamoja na uongozi, utawala, mifumo ya Tehama, kanzudata za TEHAMA pamoja na mitandao ya kompyuta.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align: justify;\\\">Katika vipindi vyake mbalimbali vya kuhudumu, Korojelo ametoa machapisho kadhaa katika maeneo ya TEHAMA na menejimenti.<\\/p>\",\"content_en\":\"<p style=\\\"text-align: justify;\\\">Sijali Petro Korojelo has been the acting Director of Public Service in Service Training since February 2023. In the past, he served as the manager of programme at the TPSC Mtwara campus (2016), a campus director for the Singida and Tanga campuses (2017 - 2019), and an acting director of the Global Learning Centre (2020 - 2022). Furthermore, he once served as a researcher at the Informatics Institute of the University of Amsterdam, Netherlands (2011 - 2012).<\\/p>\\r\\n\\r\\n<p style=\\\"text-align: justify;\\\">Korojelo holds a bachelor&#39;s and a master&rsquo;s degree in Computer Science from the University of Dar es Salaam. He has also attended several professional training programme in the areas of computing and ICT. His areas of interest include management, administration, information systems, databases, computer networking, and cloud computing.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align: justify;\\\">During the course of his actions, Korojelo has published several articles in the areas of management, computing, and ICT. Some of his publications include Enhanced Authentication on Targeted Online Surveys: A Case of Online Course Evaluation System (at the International Journal on New Computer Architectures and Their Applications), Online&nbsp;Surveys System with Enhanced Authentication Intelligence: A Case of Online Course Evaluation System (at Springer), and Uplifting Motivation of Tanzanian Public Service Personnel for Improved Service Delivery: The Reflection of Public Service Motivation Theory (at the International Journal of African and Asian.<\\/p>\",\"photo_url\":\"4cb1079629c181bd699f9ba18e9a057a.jpeg\",\"email\":\"sijali.korojelo@tpsc.go.tz\",\"phone\":\"+255 22 2152982\",\"created_at\":\"2023-12-14T11:52:23.000000Z\",\"updated_at\":\"2024-01-05T13:40:22.000000Z\",\"slug\":\"director-2\"}','2024-01-09 05:34:52','2024-01-09 05:34:52'),(1496,6,'Campus','store','154.74.127.154','http://demo81.eganet.go.tz/tpsc/cms/campuses','{\"title_sw\":\"Kampasi  ya Singida\",\"title_en\":\"Singida Campus\",\"particulars_sw\":\"<p style=\\\"text-align: justify;\\\">Tanzania Public Service College &ndash; Singida Campus is one of the six (6) Campuses of the Tanzania Public Service College (TPSC). The Campus was established in July 2011, being the fourth campus to be established among the six campuses of TPSC. Its establishment was a result of instructions issued by Prime Minister Hon. Mizengo Pinda on 23rd November 2009 during inauguration of Tanzania Public Service College Mtwara Campus. Singida Campus is located along airport road in Mandewa Ward at Singida Municipality &ndash;Singida Region.&nbsp;<\\/p>\",\"particulars_en\":\"<p style=\\\"text-align: justify;\\\">Tanzania Public Service College &ndash; Singida Campus is one of the six (6) Campuses of the Tanzania Public Service College (TPSC). The Campus was established in July 2011, being the fourth campus to be established among the six campuses of TPSC. Its establishment was a result of instructions issued by Prime Minister Hon. Mizengo Pinda on 23rd November 2009 during inauguration of Tanzania Public Service College Mtwara Campus. Singida Campus is located along airport road in Mandewa Ward at Singida Municipality &ndash;Singida Region.<\\/p>\",\"course_offered_sw\":\"<p style=\\\"text-align: justify;\\\">The Campus offers a wide range of programmes from Certificate to Diploma levels. The courses offered include Basic Technician Certificate in Secretarial Studies (BTCSS) &ndash; NTA 4; Basic Technician Certificate in Records Management (BTCRM) - NTA 4; Basic Technician Certificate in Human Resource Management (BTCHRM) &ndash; NTA 4; Basic Technician Certificate in Public Administration (BTCPA) &ndash; NTA 4; Ordinary Diploma in Secretarial Studies (ODSS) &ndash; NTA 5 &amp; 6; Ordinary Diploma in Records Management (ODRM) (NTA 5 &amp; 6); Ordinary Diploma in Public Administration (ODPA) &ndash; NTA 5 &amp; 6 and Ordinary Diploma in Human Resource Management (ODHRM)&ndash;NTA 5 &amp; 6. Likewise, the Campus offers short courses and consultant services to different stakeholders in the public and private sector. It is also the centre for coordinating and conducting Public Service Examinations (PSE) to public servants. Singida Campus follows Competence Based Education Training (CBET) curricula and positions itself to practice all its endeavors at the highest level of standards<\\/p>\",\"course_offered_en\":\"<p style=\\\"text-align: justify;\\\">The Campus offers a wide range of programmes from Certificate to Diploma levels. The courses offered include Basic Technician Certificate in Secretarial Studies (BTCSS) &ndash; NTA 4; Basic Technician Certificate in Records Management (BTCRM) - NTA 4; Basic Technician Certificate in Human Resource Management (BTCHRM) &ndash; NTA 4; Basic Technician Certificate in Public Administration (BTCPA) &ndash; NTA 4; Ordinary Diploma in Secretarial Studies (ODSS) &ndash; NTA 5 &amp; 6; Ordinary Diploma in Records Management (ODRM) (NTA 5 &amp; 6); Ordinary Diploma in Public Administration (ODPA) &ndash; NTA 5 &amp; 6 and Ordinary Diploma in Human Resource Management (ODHRM)&ndash;NTA 5 &amp; 6. Likewise, the Campus offers short courses and consultant services to different stakeholders in the public and private sector. It is also the centre for coordinating and conducting Public Service Examinations (PSE) to public servants. Singida Campus follows Competence Based Education Training (CBET) curricula and positions itself to practice all its endeavors at the highest level of standards<\\/p>\",\"student_services_sw\":\"<p style=\\\"text-align: justify;\\\">To enable students acquire necessary skills for professionalism and career development in different areas of specialization the campus has ensured-:<\\/p>\\r\\n\\r\\n<p style=\\\"text-align: justify;\\\">a)&nbsp;&nbsp; &nbsp;Reliable catering and banking services to facilitate &nbsp;availability of food and banking services at affordable cost<br \\/>\\r\\nb)&nbsp;&nbsp; &nbsp;Good climatic condition surrounded by greenish environment that makes learning and studying environment conducive.&nbsp;<br \\/>\\r\\nc)&nbsp;&nbsp; &nbsp;The accommodation services: The campus offers a range of quality accommodation services both on-campus and off-campus. Off campus accommodation services are handled in collaboration with private owners of hostels but under the management and control of Campus management. The services are charged at the rate of TZS. 150,000-200,000\\/= per &nbsp;semester&nbsp;<br \\/>\\r\\nd)&nbsp;&nbsp; &nbsp;Government and private owned health facilities including Singida Regional Referral Hospital, Singida Municipal Hospital, Tumaini Health Centre and MICO Health Centre that provide high quality, responsive and sustainable health services are all located nearby the Campus.<br \\/>\\r\\ne)&nbsp;&nbsp; &nbsp;Religious facilities including churches for Christian students and Mosque for Muslims students are available for enhancing students&rsquo; spiritual life. Apart from that, campus provides building for worshipping services for all Christians and Muslims students who need extra religious services.<br \\/>\\r\\nf)&nbsp;&nbsp; &nbsp;Sports and games facilities that aim to promote overall health and mental ability of the students and teachers. Sports facilities available include football pitches, netball, and volleyball among others.&nbsp;<br \\/>\\r\\ng)&nbsp;&nbsp; &nbsp;Health Insurance services which are provided in collaboration with National Health Insurance Funds (NHIF) are ensured to students for ease and quality acquisition of health services at the affordable cost.<br \\/>\\r\\nh)&nbsp;&nbsp; &nbsp;Counseling services that aims to offer services targeting health related concerns; academic (teaching and learning) concerns; psycho-social concerns; economic and financial concerns and other personal concerns. Likewise, the section commensurate with provision of high-quality services that nurture students to engage in academic and social development effectively.<\\/p>\",\"student_services_en\":\"<p style=\\\"text-align: justify;\\\">To enable students acquire necessary skills for professionalism and career development in different areas of specialization the campus has ensured-:<\\/p>\\r\\n\\r\\n<p style=\\\"text-align: justify;\\\">a)&nbsp;&nbsp; &nbsp;Reliable catering and banking services to facilitate &nbsp;availability of food and banking services at affordable cost<br \\/>\\r\\nb)&nbsp;&nbsp; &nbsp;Good climatic condition surrounded by greenish environment that makes learning and studying environment conducive.&nbsp;<br \\/>\\r\\nc)&nbsp;&nbsp; &nbsp;The accommodation services: The campus offers a range of quality accommodation services both on-campus and off-campus. Off campus accommodation services are handled in collaboration with private owners of hostels but under the management and control of Campus management. The services are charged at the rate of TZS. 150,000-200,000\\/= per &nbsp;semester&nbsp;<br \\/>\\r\\nd)&nbsp;&nbsp; &nbsp;Government and private owned health facilities including Singida Regional Referral Hospital, Singida Municipal Hospital, Tumaini Health Centre and MICO Health Centre that provide high quality, responsive and sustainable health services are all located nearby the Campus.<br \\/>\\r\\ne)&nbsp;&nbsp; &nbsp;Religious facilities including churches for Christian students and Mosque for Muslims students are available for enhancing students&rsquo; spiritual life. Apart from that, campus provides building for worshipping services for all Christians and Muslims students who need extra religious services.<br \\/>\\r\\nf)&nbsp;&nbsp; &nbsp;Sports and games facilities that aim to promote overall health and mental ability of the students and teachers. Sports facilities available include football pitches, netball, and volleyball among others.&nbsp;<br \\/>\\r\\ng)&nbsp;&nbsp; &nbsp;Health Insurance services which are provided in collaboration with National Health Insurance Funds (NHIF) are ensured to students for ease and quality acquisition of health services at the affordable cost.<br \\/>\\r\\nh)&nbsp;&nbsp; &nbsp;Counseling services that aims to offer services targeting health related concerns; academic (teaching and learning) concerns; psycho-social concerns; economic and financial concerns and other personal concerns. Likewise, the section commensurate with provision of high-quality services that nurture students to engage in academic and social development effectively.<\\/p>\",\"facilities_sw\":\"<p style=\\\"text-align:justify\\\">The campus provides academic services in well ventilated and modern classrooms, laboratories (both typing and computer laboratories) with a well-equipped library that contain modern and current books, internet and learning facilities. Teaching and learning activities are facilitated by well and highly qualified, motivated, committed and talented facilitators who are eager to serve the customers with high level of loyalty and integrity.&nbsp;<\\/p>\",\"facilities_en\":\"<p style=\\\"text-align: justify;\\\">The campus provides academic services in well ventilated and modern classrooms, laboratories (both typing and computer laboratories) with a well-equipped library that contain modern and current books, internet and learning facilities. Teaching and learning activities are facilitated by well and highly qualified, motivated, committed and talented facilitators who are eager to serve the customers with high level of loyalty and integrity.&nbsp;<\\/p>\",\"contacts_sw\":null,\"contacts_en\":null,\"slug\":\"singida-campus\"}','2024-01-09 18:55:29','2024-01-09 18:55:29'),(1497,6,'Administration','update','154.74.127.154','http://demo81.eganet.go.tz/tpsc/cms/administration/28','{\"id\":28,\"salutation_en\":\"Dr.\",\"salutation_sw\":\"Dkt.\",\"fullname\":\"Emmanuel Tandika\",\"position\":\"0\",\"title_sw\":\"Mkurugenzi wa Kampasi - Singida\",\"title_en\":\"Campus Director - Singida\",\"content_sw\":\"<p style=\\\"text-align: justify;\\\">Dr. Emmanuel Tandika (PhD) is a lecturer at the Tanzania Public Service College (TPSC). He obtained his undergraduate degree (Bachelor of Arts in Education) in 2005 from the University of Dar es Salaam. He received his postgraduate Diploma in Human Resource Management in 2008 from the Institute of Finance Management (IFM) under the mentorship and guidance of Dr. Mwanjabala. He also received Master degree in Business Administration (MBA) with specialization in Human Resource management in 2010 from the University of Dar es Salaam. Dr. Tandika received his PhD in Business Administration with specialization in Human Resource Management in 2022 from the University of Dar es Salaam. In 2023, he was promoted from Assistant Lecturer to Lecturer level.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align: justify;\\\"><br \\/>\\r\\nDr. Tandika has attended various career development trainings, conferences, workshops and seminars including international conferences on African Entrepreneurship and Small Business Development, Business Process Re-Engineering , Research and Consultancy Skills Development, Application of Free and Open Source Software to Enhance Research Capacity and E-Learning in Tanzania, Qualitative Data Analysis Using MAXQDA 2020 package, General Applicability of New Labour Laws, Competence-Based Learning Cursus (CEBET), Competency-Based Employee Selection Programme, Training on Advocacy and Lobbying and other National and international trainings.<br \\/>\\r\\nDr. Tandika has been involved in facilitating various Management and Human Resource programmes in various colleges including Institute of Social Work (DSM), Tanzania Institute of Accountancy (DSM) and Tanzania Public Service College (DSM Campus). He has been involved in various collaborative research projects including the Research on Minimum Wage Bills conducted by TPSC and the ongoing Research in finding out the source of conflict among presidential appointees in Local Government Authorities in Tanzania. He has published papers in national and international journals including ORSEA Journal and Journal of Healthcare Administration. He was awarded a certificate of appreciation as the first winner in essay completion East Africa on &ldquo;Kiswahili, Utandawazi na Umoja wa Africa&rdquo; in 2005 and a certificate of appreciation as the first winner in Tanzania in essay competition on &ldquo;Child Domestic Labour&rdquo; conducted by Kuleana, Mwanza in 2004.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align: justify;\\\"><br \\/>\\r\\n&nbsp;In Management, Dr. Tandika has been promoted to various positions. He served as a Coordinator in the Department of Records, Archives and Information Studies (2012-2013); Manager of Programmes (MOP) &ndash; TPSC- DSM Campus (2013-2014); Quality Assurance Manager (2014-2015) and currently he serves as a Campus Director, TPSC-Singida Campus.&nbsp;<br \\/>\\r\\n&nbsp;<\\/p>\",\"content_en\":\"<p style=\\\"text-align:justify\\\">Dr. Emmanuel Tandika (PhD) is a lecturer at the Tanzania Public Service College (TPSC). He obtained his undergraduate degree (Bachelor of Arts in Education) in 2005 from the University of Dar es Salaam. He received his postgraduate Diploma in Human Resource Management in 2008 from the Institute of Finance Management (IFM) under the mentorship and guidance of Dr. Mwanjabala. He also received Master degree in Business Administration (MBA) with specialization in Human Resource management in 2010 from the University of Dar es Salaam. Dr. Tandika received his PhD in Business Administration with specialization in Human Resource Management in 2022 from the University of Dar es Salaam. In 2023, he was promoted from Assistant Lecturer to Lecturer level.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><br \\/>\\r\\nDr. Tandika has attended various career development trainings, conferences, workshops and seminars including international conferences on African Entrepreneurship and Small Business Development, Business Process Re-Engineering , Research and Consultancy Skills Development, Application of Free and Open Source Software to Enhance Research Capacity and E-Learning in Tanzania, Qualitative Data Analysis Using MAXQDA 2020 package, General Applicability of New Labour Laws, Competence-Based Learning Cursus (CEBET), Competency-Based Employee Selection Programme, Training on Advocacy and Lobbying and other National and international trainings.<br \\/>\\r\\nDr. Tandika has been involved in facilitating various Management and Human Resource programmes in various colleges including Institute of Social Work (DSM), Tanzania Institute of Accountancy (DSM) and Tanzania Public Service College (DSM Campus). He has been involved in various collaborative research projects including the Research on Minimum Wage Bills conducted by TPSC and the ongoing Research in finding out the source of conflict among presidential appointees in Local Government Authorities in Tanzania. He has published papers in national and international journals including ORSEA Journal and Journal of Healthcare Administration. He was awarded a certificate of appreciation as the first winner in essay completion East Africa on &ldquo;Kiswahili, Utandawazi na Umoja wa Africa&rdquo; in 2005 and a certificate of appreciation as the first winner in Tanzania in essay competition on &ldquo;Child Domestic Labour&rdquo; conducted by Kuleana, Mwanza in 2004.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><br \\/>\\r\\n&nbsp;In Management, Dr. Tandika has been promoted to various positions. He served as a Coordinator in the Department of Records, Archives and Information Studies (2012-2013); Manager of Programmes (MOP) &ndash; TPSC- DSM Campus (2013-2014); Quality Assurance Manager (2014-2015) and currently he serves as a Campus Director, TPSC-Singida Campus.&nbsp;<\\/p>\",\"photo_url\":\"1191473d16cf015cd4c3b987396d1942.jpeg\",\"email\":\"emmanuel.tandika@tpsc.go.tz\",\"phone\":\"0784403772\",\"created_at\":\"2023-12-19T08:20:51.000000Z\",\"updated_at\":\"2023-12-19T10:43:37.000000Z\",\"slug\":\"director-4\"}','2024-01-09 18:58:03','2024-01-09 18:58:03'),(1498,6,'Administration','update','41.222.181.211','http://demo81.eganet.go.tz/tpsc/cms/administration/17','{\"id\":17,\"salutation_en\":\"Ms\",\"salutation_sw\":\"Ms\",\"fullname\":\"Juslina Tuzza\",\"position\":\"0\",\"title_sw\":\"Mkurugenzi wa Kampasi ya Mtwara\",\"title_en\":\"Campus Director -  Mtwara\",\"content_sw\":\"<p style=\\\"text-align: justify;\\\">Ms. Juslina M.Tuzza is An Assistant Lecturer and Campus Director at the Tanzania Public Service College (TPSC) - Mtwara Campus. &nbsp;She is a highly accomplished professional in the fields of education (Language). She holds a Master&rsquo;s Degree of Arts with Education from the University of Dar es Salaam, Tanzania. She also holds a Bachelor of Arts with Education from the University of St. John Dodoma-Tanzania and a Diploma in Education from the Marangu Teachers&rsquo; College- Kilimanjaro, Tanzania.<br \\/>\\r\\nIn March 2021, she joined Tanzania Public Service Collage as Assistant lecturer, where latter promoted to the position of Manager of Program at Campus level, a position she held until February 2022, when she was appointed as Campus Director at Mtwara campus working from February 2022 to date<\\/p>\\r\\n\\r\\n<p style=\\\"text-align: justify;\\\"><br \\/>\\r\\nIn her role as the Campus Director at Tanzania Public Service College- Mtwara, Ms. Tuzza is responsible for the implementation of all policies and initiatives aimed at ensuring the efficiency and accountability of the campus staff and students in implementing their responsibilities to make sure specific and general goals of the organization are well attained. She is highly dedicated and her successful career path and an upward mobility that is matched and can only be explained by factors of individual motivation and personal discipline as well as sense of self-awareness fueled by her individual strong and persistence philosophy of life.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align: justify;\\\"><br \\/>\\r\\nMs. Juslina M Tuzza has a remarkable academic background, combined with her experiences and skills have made significant contributions to the development and advancement of the Tanzania Public College at Mtwara Campus and Nation at large. Besides, She has successfully prepared papers for publication; The Perception of Job seekers on the Adoption and Use of E-Recruitment in Tanzania:A case study of Ajira Portal, Challenges of &nbsp;&lsquo; Gheto&rsquo; life to Students in Vocational &nbsp;Education and Training Institutions; The case of Mtwara &nbsp;region and &nbsp;Exploring &nbsp;the Influence of Parenting &nbsp;Style on Adolescents&rsquo; Sexual Behavior (Prostitution) in Chris Mwangi&rsquo;s The Operator. Further underscoring her unwavering commitment to advancing the fields of education and personal development. She frequently involved in personal academic studies online and attending short course training particularly on data collection and analysis.<\\/p>\",\"content_en\":\"<p style=\\\"text-align:justify\\\">Ms. Juslina M.Tuzza is An Assistant Lecturer and Campus Director at the Tanzania Public Service College (TPSC) - Mtwara Campus. &nbsp;She is a highly accomplished professional in the fields of education (Language). She holds a Master&rsquo;s Degree of Arts with Education from the University of Dar es Salaam, Tanzania. She also holds a Bachelor of Arts with Education from the University of St. John Dodoma-Tanzania and a Diploma in Education from the Marangu Teachers&rsquo; College- Kilimanjaro, Tanzania.<br \\/>\\r\\nIn March 2021, she joined Tanzania Public Service Collage as Assistant lecturer, where latter promoted to the position of Manager of Program at Campus level, a position she held until February 2022, when she was appointed as Campus Director at Mtwara campus working from February 2022 to date<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><br \\/>\\r\\nIn her role as the Campus Director at Tanzania Public Service College- Mtwara, Ms. Tuzza is responsible for the implementation of all policies and initiatives aimed at ensuring the efficiency and accountability of the campus staff and students in implementing their responsibilities to make sure specific and general goals of the organization are well attained. She is highly dedicated and her successful career path and an upward mobility that is matched and can only be explained by factors of individual motivation and personal discipline as well as sense of self-awareness fueled by her individual strong and persistence philosophy of life.<\\/p>\\r\\n\\r\\n<p style=\\\"text-align:justify\\\"><br \\/>\\r\\nMs. Juslina M Tuzza has a remarkable academic background, combined with her experiences and skills have made significant contributions to the development and advancement of the Tanzania Public College at Mtwara Campus and Nation at large. Besides, She has successfully prepared papers for publication; The Perception of Job seekers on the Adoption and Use of E-Recruitment in Tanzania:A case study of Ajira Portal, Challenges of &nbsp;&lsquo; Gheto&rsquo; life to Students in Vocational &nbsp;Education and Training Institutions; The case of Mtwara &nbsp;region and &nbsp;Exploring &nbsp;the Influence of Parenting &nbsp;Style on Adolescents&rsquo; Sexual Behavior (Prostitution) in Chris Mwangi&rsquo;s The Operator. Further underscoring her unwavering commitment to advancing the fields of education and personal development. She frequently involved in personal academic studies online and attending short course training particularly on data collection and analysis.<\\/p>\",\"photo_url\":\"c169c419cbfa83870ad64df47a602160.jpeg\",\"email\":\"juslina.tuzza@tpsc.go.tz\",\"phone\":\"+255 22 2152982\",\"created_at\":\"2023-12-14T11:55:16.000000Z\",\"updated_at\":\"2023-12-19T09:52:59.000000Z\",\"slug\":\"campus-manager-mtwara-campus\"}','2024-01-11 03:54:06','2024-01-11 03:54:06'),(1499,6,'Administration','update','41.222.181.211','http://demo81.eganet.go.tz/tpsc/cms/administration/17','{\"id\":17,\"salutation_en\":\"Ms\",\"salutation_sw\":\"Ms\",\"fullname\":\"Juslina Tuzza\",\"position\":\"0\",\"title_sw\":\"Mkurugenzi wa Kampasi ya Mtwara\",\"title_en\":\"Campus Director -  Mtwara\",\"content_sw\":\"<p style=\\\"text-align:justify\\\">Ms. Juslina M.Tuzza is An Assistant Lecturer and Ca